is_installed(){ find "$KCP_INSTALL_DIR" -maxdepth 1 -name '*.json' 2>/dev/null | grep -q . || find "$UDP2RAW_INSTALL_DIR" -maxdepth 1 -name '*.conf' 2>/dev/null | grep -q . || find "$SINGBOX_INSTALL_DIR" -maxdepth 1 -name '*.json' 2>/dev/null | grep -q .; }

PUBLIC_IP_CACHE="/etc/ax-public-ip"
PUBLIC_IP_TTL=86400 # 缓存有效期 24 小时

# -----------------------------------------------------------------------------
# 获取本机公网 IP 地址 (带文件缓存)
# -----------------------------------------------------------------------------
get_public_ip() {
    if [[ -n "$PUBLIC_IP" ]]; then echo "$PUBLIC_IP"; return; fi
    # 尝试从缓存文件读取 (检查 TTL)
    if [[ -f "$PUBLIC_IP_CACHE" ]]; then
        local cache_time=$(head -1 "$PUBLIC_IP_CACHE" 2>/dev/null)
        local now=$(date +%s)
        if [[ -n "$cache_time" && $((now - cache_time)) -lt $PUBLIC_IP_TTL ]]; then
            PUBLIC_IP=$(sed -n '2p' "$PUBLIC_IP_CACHE" 2>/dev/null)
            [[ -n "$PUBLIC_IP" ]] && { echo "$PUBLIC_IP"; return; }
        fi
    fi
    PUBLIC_IP=$(curl -s4m2 $PUBLIC_IP_SERVICE_1 || curl -s4m2 $PUBLIC_IP_SERVICE_2)
    if [[ -z "$PUBLIC_IP" ]]; then PUBLIC_IP="127.0.0.1"; yellow "获取公网 IP 失败，将使用 127.0.0.1 作为备用。" >&2; fi
    # 写入缓存 (timestamp + IP)
    echo "$(date +%s)" > "$PUBLIC_IP_CACHE" && echo "$PUBLIC_IP" >> "$PUBLIC_IP_CACHE"
    echo "$PUBLIC_IP"
}

# -----------------------------------------------------------------------------
# 统一检测与安装系统依赖和核心程序
# -----------------------------------------------------------------------------
install_dependencies_and_programs(){
    echo ""
    log "正在检测 系统依赖组件与核心程序..."
    echo ""
    
    # ========== 第一阶段：检测系统依赖组件 ==========
    local packages_to_install=()
    local missing_deps=()
    
    # 定义需要检查的依赖列表
    declare -A dep_map=(
        ["curl"]="curl"
        ["wget"]="wget"
        ["tar"]="tar"
        ["unzip"]="unzip"
        ["jq"]="jq"
        ["openssl"]="openssl"
        ["uuidgen"]="uuid-runtime"
        ["nano"]="nano"
        ["iptables"]="iptables"
        ["socat"]="socat"
    )
    
    # 检查 dig 命令 (DNS 工具)
    if ! command -v dig &>/dev/null; then
        if command -v apt-get &>/dev/null; then
            dep_map["dig"]="dnsutils"
        elif command -v yum &>/dev/null || command -v dnf &>/dev/null; then
            dep_map["dig"]="bind-utils"
        fi
    fi
    
    # 检测缺失的依赖
    for cmd in "${!dep_map[@]}"; do
        if ! command -v "$cmd" &>/dev/null; then
            packages_to_install+=("${dep_map[$cmd]}")
            missing_deps+=("$cmd")
        fi
    done
    
    # ========== 第二阶段：安装系统依赖组件 ==========
    if [ ${#packages_to_install[@]} -gt 0 ]; then
        echo ""
        yellow "开始下载安装 系统依赖组件..."
        echo ""
        
        # 逐个显示要安装的包
        for pkg in "${packages_to_install[@]}"; do
            cyan "  » 安装 $pkg"
        done
        echo ""
        
        # 执行实际安装
        if (apt-get update && apt-get install -y "${packages_to_install[@]}") >/dev/null 2>&1 || \
           (yum install -y epel-release && yum install -y "${packages_to_install[@]}") >/dev/null 2>&1 || \
           (dnf install -y "${packages_to_install[@]}") >/dev/null 2>&1; then
            green "✓ 系统依赖组件安装完成！"
        else
            red "✗ 部分系统依赖组件安装失败"
            yellow "请手动执行: apt install ${packages_to_install[*]}"
            return 1
        fi
    else
        green "✓ 所有系统依赖组件已就绪"
    fi
    
    # ========== 第三阶段：检测与下载核心程序 ==========
    # 检查各核心程序文件是否存在
    local need_download=false
    local kcp_ok=true; if [[ ! -f "$KCP_INSTALL_DIR/kcptun_server" ]]; then kcp_ok=false; need_download=true; fi
    local udp_ok=true; if [[ ! -f "$UDP2RAW_INSTALL_DIR/udp2raw" ]]; then udp_ok=false; need_download=true; fi
    local singbox_ok=true; if [[ ! -f "$SINGBOX_INSTALL_DIR/sing-box" ]]; then singbox_ok=false; need_download=true; fi
    
    if [[ "$need_download" == false ]]; then
        echo ""
        green "✓ 所有核心程序已就绪"
        echo ""
        return 0
    fi
    
    # 只有需要下载时才显示此消息
    echo ""
    yellow "开始下载安装 核心程序..." 
    echo ""
    
    # 下载缺失的核心程序
    if [[ "$kcp_ok" == false || "$udp_ok" == false ]]; then
        cyan "  » 下载 KCPTUN/UDP2RAW"
        download_kcp_udp_binaries || { red "✗ KCPTUN/UDP2RAW 下载失败"; return 1; }
        green "    ✓ KCPTUN/UDP2RAW 安装完成"
    fi
    
    if [[ "$singbox_ok" == false ]]; then
        cyan "  » 下载 Sing-box"
        download_singbox_binary || { red "✗ Sing-box 下载失败"; return 1; }
        green "    ✓ Sing-box 安装完成"
    fi
    
    echo ""
    green "✓ 所有组件安装完成！"
    echo ""
    
    # ========== 第四阶段：检测与下载辅助脚本（但不执行）==========
    echo ""
    yellow "检查辅助脚本..." 
    echo ""
    
    # Derive script names from URLs
    AX_ACME_SCRIPT=$(basename "$AX_ACME_URL")
    AX_OPTZ_SCRIPT=$(basename "$AX_OPTZ_URL")

    local script_download_needed=false
    local acme_ok=true; if [[ ! -f "$AX_ACME_SCRIPT" ]]; then acme_ok=false; script_download_needed=true; fi
    local optz_ok=true; if [[ ! -f "$AX_OPTZ_SCRIPT" ]]; then optz_ok=false; script_download_needed=true; fi
    
    if [[ "$script_download_needed" == false ]]; then
        green "✓ 所有辅助脚本已就绪"
        echo ""
    else
        # 下载缺失的辅助脚本
        if [[ "$acme_ok" == false ]]; then
            cyan "  » 下载 $AX_ACME_SCRIPT"
            download_with_retry "$AX_ACME_URL" "$AX_ACME_SCRIPT" >/dev/null 2>&1 && chmod +x "$AX_ACME_SCRIPT" && green "    ✓ $AX_ACME_SCRIPT 下载完成" || yellow "    ⚠ $AX_ACME_SCRIPT 下载失败"
        fi
        
        if [[ "$optz_ok" == false ]]; then
            cyan "  » 下载 $AX_OPTZ_SCRIPT"
            download_with_retry "$AX_OPTZ_URL" "$AX_OPTZ_SCRIPT" >/dev/null 2>&1 && chmod +x "$AX_OPTZ_SCRIPT" && green "    ✓ $AX_OPTZ_SCRIPT 下载完成" || yellow "    ⚠ $AX_OPTZ_SCRIPT 下载失败"
        fi
        
        echo ""
        green "✓ 辅助脚本检查完成！"
        echo ""
    fi
}

# -----------------------------------------------------------------------------
# 带重试机制的文件下载函数
# 参数: $1=URL, $2=输出路径
# -----------------------------------------------------------------------------
download_with_retry(){
    local url=$1 output=$2 retries=3 timeout=15
    for ((i=1; i<=retries; i++)); do
        log "下载 ($i/$retries)：$url" >&2
        curl -L --connect-timeout 5 --max-time $timeout -o "$output" "$url" && return 0
        yellow "下载失败，正在重试..." >&2
    done
    red "下载失败超过 $retries 次，请检查网络。" >&2
    return 1
}

# -----------------------------------------------------------------------------
# 确保辅助脚本存在（统一下载函数）
# 参数: $1=脚本名称变量 (如: "$AX_ACME_SCRIPT")
# 参数: $2=脚本 URL
# 参数: $3=强制更新 (true/false, 默认 false)
# -----------------------------------------------------------------------------
ensure_ax_script() {
    local script_name=$1
    local script_url=$2
    local force_update=${3:-false}
    
    # 如果本地存在且不强制更新，直接返回
    if [ -f "$script_name" ] && [ "$force_update" != "true" ]; then
        return 0
    fi
    
    # 否则下载
    log "正在下载最新版本的 ${script_name}..." >&2
    download_with_retry "$script_url" "$script_name" >&2
    if [ $? -ne 0 ]; then
        red "${script_name} 下载失败。" >&2
        return 1
    fi
    chmod +x "$script_name"
    green "${script_name} 下载完成。" >&2
    return 0
}

# -----------------------------------------------------------------------------
# 查找一个未被占用的随机端口 (范围: RANDOM_PORT_MIN - RANDOM_PORT_MAX)
# -----------------------------------------------------------------------------
find_available_port() {
    local port
    while true; do
        port=$(( RANDOM % (RANDOM_PORT_MAX - RANDOM_PORT_MIN + 1) + RANDOM_PORT_MIN ))
        # 检查端口是否被占用 (ss -tuln)
        ! ss -tuln | grep -q ":${port} " && echo "$port" && return
    done
}

# -----------------------------------------------------------------------------
# 生成强密码 (优先使用 uuidgen，失败则使用 hexdump)
# -----------------------------------------------------------------------------
generate_strong_password() {
    if command -v uuidgen >/dev/null 2>&1; then
        uuidgen
    else
        log "uuidgen 未找到，生成备用 UUID..." >&2
        hexdump -n 16 -v -e '4/4 "%08x" "-" 2/2 "%04x" "-" 2/2 "%04x" "-" 2/2 "%04x" "-" 6/6 "%012x"' /dev/urandom | head -c 36
    fi
}

# -----------------------------------------------------------------------------
# 生成自签名证书 (用于 Sing-box Hysteria2 入站 TLS)
# -----------------------------------------------------------------------------
generate_self_signed_cert() {
    if [[ -s "$HY2_CERT_PATH" && -s "$HY2_KEY_PATH" ]]; then return; fi
    log "正在为 ${HY2_SNI} 生成自签名证书..."
    mkdir -p "$(dirname "$HY2_KEY_PATH")"
    # 生成私钥
    openssl ecparam -name prime256v1 -genkey -noout -out "$HY2_KEY_PATH"
    chmod 600 "$HY2_KEY_PATH"
    if [[ $? -ne 0 ]]; then red "错误: openssl ecparam 命令执行失败。"; exit 1; fi
    # 生成证书
    openssl req -new -x509 -days 36500 -key "$HY2_KEY_PATH" -out "$HY2_CERT_PATH" -subj "/CN=${HY2_SNI}" -nodes
    if [[ $? -ne 0 ]]; then red "错误: openssl req 命令执行失败。"; exit 1; fi
    if [[ ! -s "$HY2_CERT_PATH" || ! -s "$HY2_KEY_PATH" ]]; then red "错误: 证书文件生成失败或为空！"; exit 1; fi
    green "证书生成完毕。"
}

# -----------------------------------------------------------------------------
# 处理密码输入逻辑
# 支持自动生成、手动输入和保存上次使用的密码
# -----------------------------------------------------------------------------
handle_password_input() {
    local service_type=$1; local pass_file; local last_pass=""
    # 根据服务类型确定密码保存文件路径
    case "$service_type" in
        kcptun) mkdir -p "$KCP_INSTALL_DIR"; pass_file="$KCP_INSTALL_DIR/last_${service_type}_pass.txt" ;;
        udp2raw) mkdir -p "$UDP2RAW_INSTALL_DIR"; pass_file="$UDP2RAW_INSTALL_DIR/last_${service_type}_pass.txt" ;;
        shadowsocks) mkdir -p "$SINGBOX_INSTALL_DIR"; pass_file="$SINGBOX_INSTALL_DIR/last_ss_pass.txt" ;;
        hysteria2) mkdir -p "$SINGBOX_INSTALL_DIR"; pass_file="$SINGBOX_INSTALL_DIR/last_hy2_pass.txt" ;;
    esac
    
    # 读取上次保存的密码 (如果存在)
    if [[ -f "$pass_file" ]]; then last_pass=$(cat "$pass_file"); fi
    local display_pass=${last_pass:-"无"}
    local prompt_text="请输入密码"

    # 为 SS-2022 提供特定提示
    if [[ "$service_type" == "shadowsocks" ]]; then
         yellow "注意: SS-2022 (如 $SS_DEFAULT_METHOD) 必须使用 Base64 密钥。" >&2
         prompt_text="请输入 Base64 密钥"
    fi

    read -p "${prompt_text} (原有: ${display_pass}, 回车自动生成): " password

    if [[ -z "$password" ]]; then
        # 用户未输入，使用自动生成逻辑
        if [[ "$service_type" == "shadowsocks" ]]; then
            # SS-2022 需要特定长度的 Base64 密钥
            local key_length=32 # 默认 32 字节 (用于 256-gcm)
            if [[ "$SS_DEFAULT_METHOD" == *"128-gcm"* ]]; then
                key_length=16 # 16 字节 (用于 128-gcm)
            fi
            
            if ! command -v openssl &>/dev/null; then
                red "错误: openssl 命令未找到，无法生成 SS-2022 密钥！" >&2
                return 1
            fi
            password=$(openssl rand -base64 $key_length)
            green "已为您自动生成 SS-2022 Base64 密钥: $password" >&2
        else
            # 其他服务使用通用强密码生成
            password=$(generate_strong_password)
            green "已为您自动生成随机密码: $password" >&2
        fi
    else
        # 用户手动输入了密码
        if [[ "$service_type" == "shadowsocks" ]]; then
            yellow "警告: 已使用您输入的 '$password'。" >&2
            yellow "如果 Shadowsocks 启动失败，请检查这是否是有效的 Base64 密钥。" >&2
        fi
    fi

    # 保存密码到文件并设置权限
    echo "$password" > "$pass_file"
    chmod 600 "$pass_file"
    echo "$password"
}

# =============================================================================
# 11. 参数收集公共函数 (交互式)
# =============================================================================

# -----------------------------------------------------------------------------
# 收集 UDP2RAW 参数
# 返回格式: raw_mode|cipher_mode|auth_mode
# -----------------------------------------------------------------------------
collect_udp2raw_params() {
    read -p "raw_mode [faketcp/udp/icmp] (默认 faketcp): " raw_mode >&2
    raw_mode=${raw_mode:-faketcp}
    
    read -p "cipher_mode [aes128cbc/xor/none] (默认 aes128cbc): " cipher_mode >&2
    cipher_mode=${cipher_mode:-aes128cbc}
    
    read -p "auth_mode [hmac_sha1/simple/md5] (默认 hmac_sha1): " auth_mode >&2
    auth_mode=${auth_mode:-hmac_sha1}
    
    echo "$raw_mode|$cipher_mode|$auth_mode"
}

# -----------------------------------------------------------------------------
# 收集 KCPTUN 参数
# 返回格式: mode|crypt|tcp_enabled|mtu|sndwnd|rcvwnd
# -----------------------------------------------------------------------------
collect_kcptun_params() {

    read -p "MTU (默认 1200): " mtu >&2
    mtu=${mtu:-1200}
    
    read -p "sndwnd (默认 512): " sndwnd >&2
    sndwnd=${sndwnd:-512}
    
    read -p "rcvwnd (默认 2048): " rcvwnd >&2
    rcvwnd=${rcvwnd:-2048}
    read -p "mode [fast/fast2/fast3/normal/manual] (默认 $KCPTUN_DEFAULT_MODE): " mode >&2
    mode=${mode:-$KCPTUN_DEFAULT_MODE}
    
    read -p "crypt [aes-128/aes-192/aes-256] (默认 aes-128): " crypt >&2
    crypt=${crypt:-aes-128}
    
    read -p "tcp [true/false] (默认 false): " tcp_enabled >&2
    tcp_enabled=${tcp_enabled:-false}
       
    echo "$mode|$crypt|$tcp_enabled|$mtu|$sndwnd|$rcvwnd"
}


# -----------------------------------------------------------------------------
# WARP WireGuard 注册 (通过 Cloudflare API 自动获取密钥对与地址)
# 输出: 将 WARP 密钥写入 $SINGBOX_INSTALL_DIR/.warp_wireguard.json
# -----------------------------------------------------------------------------
register_warp_wireguard() {
    if ! command -v wg &>/dev/null; then
        red "错误: wireguard-tools 未安装，无法生成 WARP WireGuard 密钥。"
        return 1
    fi
    local warp_key_file="$SINGBOX_INSTALL_DIR/.warp_wireguard.json"
    mkdir -p "$SINGBOX_INSTALL_DIR"
    
    # 生成 WireGuard 密钥对
    local wg_private=$(wg genkey)
    local wg_public=$(echo "$wg_private" | wg pubkey)
    
    # 调用 Cloudflare WARP API 注册
    local api_result=$(curl -s --connect-timeout 10 \
        "https://api.cloudflareclient.com/v0a$(printf '%04d' $((RANDOM % 10000)))reg" \
        -H "Content-Type: application/json" \
        -d "{\"key\": \"${wg_public}\", \"install_id\": \"\", \"fcm_token\": \"\", \"warp_enabled\": false, \"locale\": \"zh_CN\"}")
    
    local client_id=$(echo "$api_result" | jq -r '.client_id // empty' 2>/dev/null)
    local wg_private_key=$(echo "$api_result" | jq -r '.config.interface.private_key // empty' 2>/dev/null)
    # 处理 v4 地址：API 返回的可能是 null/空，使用 jq 的 // 仅对 null 生效，
    # 额外检查空字符串
    local wg_address_v4=$(echo "$api_result" | jq -r '.config.interface.addresses.v4 // empty' 2>/dev/null)
    if [[ -z "$wg_address_v4" || "$wg_address_v4" == "null" ]]; then
        wg_address_v4="172.16.0.2"
    fi
    local wg_address_v6=$(echo "$api_result" | jq -r '.config.interface.addresses.v6 // empty' 2>/dev/null)
    
    # 若 API 返回了服务端分配的私钥则使用之，否则用本地生成的
    if [[ -z "$wg_private_key" || "$wg_private_key" == "null" ]]; then
        wg_private_key="$wg_private"
    fi
    
    # 提取 IPv6 后缀 (最后 4 段)
    local ipv6_suffix=""
    if [[ -n "$wg_address_v6" && "$wg_address_v6" != "null" ]]; then
        ipv6_suffix=$(echo "$wg_address_v6" | sed 's|/128||' | awk -F: '{print $5":"$6":"$7":"$8}')
    fi
    if [[ -z "$ipv6_suffix" ]]; then
        # 回退: 从客户端地址派生
        ipv6_suffix=$(echo "$client_id" | md5sum 2>/dev/null | head -c 8 | sed 's/\(....\)\(....\)/\1:\2/')
        ipv6_suffix="100:$(printf '%x' $RANDOM):$(printf '%x' $RANDOM):$(printf '%x' $RANDOM)"
    fi
    
    # 写入密钥文件
    cat > "$warp_key_file" <<EOF
{
    "private_key": "$wg_private_key",
    "address_v4": "$wg_address_v4/32",
    "address_v6": "2606:4700:110:${ipv6_suffix}/128",
    "reserved": [0, 0, 0]
}
EOF
    chmod 600 "$warp_key_file"
    green "✓ WARP WireGuard 注册成功！密钥已保存至 $warp_key_file"
    green "  Private key: $wg_private_key"
    green "  IPv4: $wg_address_v4/32"
    green "  IPv6: 2606:4700:110:${ipv6_suffix}/128"
    
}

# -----------------------------------------------------------------------------
# 从密钥文件加载 WARP WireGuard 配置到模板
# -----------------------------------------------------------------------------
apply_warp_wireguard_config() {
    local warp_key_file="$SINGBOX_INSTALL_DIR/.warp_wireguard.json"
    if [[ ! -f "$warp_key_file" ]]; then
        red "错误: WARP WireGuard 密钥文件不存在。请先执行 register_warp_wireguard。"
        return 1
    fi
    local block=$SINGBOX_WARP_WIREGUARD_ENDPOINT
    local addr=$(jq -r '.address_v4 // "172.16.0.2/32"' "$warp_key_file" 2>/dev/null)
    if [[ -z "$addr" || "$addr" == "null" || "$addr" == "/32" ]]; then
        addr="172.16.0.2/32"
    fi
    block=${block/__WARP_ADDRESS__/$addr}
    block=${block/__WARP_PRIVATE_KEY__/$(jq -r '.private_key' "$warp_key_file")}
    echo "$block"
}

# -----------------------------------------------------------------------------
# 读取并校验端口 (1024-65535)
# 参数: $1=提示文字, $2=变量名, $3=是否随机生成 (true/false)
# -----------------------------------------------------------------------------
read_valid_port() {
    local prompt=$1 var_name=$2 allow_random=$3
    while true; do
        read -p "$prompt" input
        if [[ -z "$input" && "$allow_random" == "true" ]]; then
            input=$(find_available_port)
            green "已为您随机选择端口: $input" >&2
            eval "$var_name='$input'"; return
        fi
        if [[ "$input" =~ ^[0-9]+$ ]] && (( input >= 1024 && input <= 65535 )); then
            eval "$var_name='$input'"; return
        fi
        red "端口必须是 1024-65535 之间的数字！" >&2
    done
}

# -----------------------------------------------------------------------------
# 查找下一个可用的实例 ID (数字)
# 遍历目录查找未使用的文件名编号
# -----------------------------------------------------------------------------
find_next_available_id() {
    local type=$1; local dir file_prefix file_ext; local i=1
    case "$type" in
        udp2raw) dir="$UDP2RAW_INSTALL_DIR"; file_prefix="udp2raw"; file_ext="conf";;
        kcptun) dir="$KCP_INSTALL_DIR"; file_prefix="kcptun"; file_ext="json";;
        singbox)
            local config_file="$SINGBOX_INSTALL_DIR/singbox.json"
            if [[ -f "$config_file" ]]; then
                local used_ids=$(jq -r '.inbounds[].tag | capture("(?<pre>vless-reality-|ss-|hy2-)(?<id>[0-9]+)") | .id' "$config_file" 2>/dev/null | sort -n)
                while true; do
                    if ! echo "$used_ids" | grep -q "^${i}$"; then echo "$i"; return; fi
                    i=$((i + 1))
                done
            else
                echo "1"; return
            fi
            ;;
    esac
    while true; do
        if [[ ! -f "$dir/${file_prefix}_${i}.${file_ext}" && ! -f "$dir/${file_prefix}_c${i}.${file_ext}" && ! -f "$dir/${file_prefix}_vc${i}.${file_ext}" && ! -f "$dir/${file_prefix}_s3c${i}.${file_ext}" ]]; then
            echo "$i"; return
        fi
        i=$((i + 1))
    done
}

# =============================================================================
# 13. 核心程序下载与安装函数
# =============================================================================

# -----------------------------------------------------------------------------
# 获取 GitHub 仓库最新 Release 标签
# -----------------------------------------------------------------------------
get_latest_github_tag() {
    local repo_name=$1
    # 使用 jq -r .tag_name 来安全、准确地获取标签名
    curl -s "$GITHUB_API_URL/$repo_name/releases/latest" | jq -r .tag_name
}

# -----------------------------------------------------------------------------
# 下载并安装 KCPTUN 和 UDP2RAW 二进制文件
# -----------------------------------------------------------------------------
download_kcp_udp_binaries(){
    mkdir -p "$KCP_INSTALL_DIR"
    mkdir -p "$UDP2RAW_INSTALL_DIR"

    local kcp_current=$(cat "$KCP_INSTALL_DIR/version.txt" 2>/dev/null)
    local udp_current=$(cat "$UDP2RAW_INSTALL_DIR/version.txt" 2>/dev/null)
    local fixed_version="Fixed-Source-v1.0.2"

    # KCPTUN - 只有版本不匹配或文件缺失才下载
    if [[ "$kcp_current" != "$fixed_version" || ! -f "$KCP_INSTALL_DIR/kcptun_server" ]]; then
        log "下载 KCPTUN (kcptun_server)..."
        download_with_retry "https://raw.githubusercontent.com/halibotee/scripts/main/package/kcptun_server" "$KCP_INSTALL_DIR/kcptun_server" && \
        chmod +x "$KCP_INSTALL_DIR/kcptun_server" && \
        echo "$fixed_version" > "$KCP_INSTALL_DIR/version.txt" || { red "KCPTUN 下载失败。"; return 1; }
    else
        green "KCPTUN 已是最新版本 ($kcp_current)"
    fi

    # UDP2RAW - 只有版本不匹配或文件缺失才下载
    if [[ "$udp_current" != "$fixed_version" || ! -f "$UDP2RAW_INSTALL_DIR/udp2raw" ]]; then
        log "下载 UDP2RAW (udp2raw_binaries.tar.gz)..."
        download_with_retry "https://raw.githubusercontent.com/halibotee/scripts/main/package/udp2raw_binaries.tar.gz" /tmp/udp2raw.tar.gz && \
        tar -xzf /tmp/udp2raw.tar.gz -C "$UDP2RAW_INSTALL_DIR" udp2raw_amd64 && \
        mv "$UDP2RAW_INSTALL_DIR/udp2raw_amd64" "$UDP2RAW_INSTALL_DIR/udp2raw" && \
        echo "$fixed_version" > "$UDP2RAW_INSTALL_DIR/version.txt" && \
        chmod +x "$UDP2RAW_INSTALL_DIR/udp2raw" || { red "UDP2RAW 下载失败。"; return 1; }
    else
        green "UDP2RAW 已是最新版本 ($udp_current)"
    fi
}

# -----------------------------------------------------------------------------
# 下载并安装 Sing-box 二进制文件
# -----------------------------------------------------------------------------
download_singbox_binary(){
    local singbox_latest=$(get_latest_github_tag "$SINGBOX_REPO")
    if [[ -z "$singbox_latest" ]]; then red "获取 Sing-box 版本号失败。"; return 1; fi
    
    mkdir -p "$SINGBOX_INSTALL_DIR"
    local singbox_current=$(cat "$SINGBOX_INSTALL_DIR/version.txt" 2>/dev/null)
    
    if [[ "$singbox_latest" != "$singbox_current" ]]; then
        log "发现 Sing-box 新版本: $singbox_latest (当前: ${singbox_current:-未知})"
        log "下载 Sing-box ($singbox_latest)..."
        local singbox_ver="${singbox_latest#v}"
        local singbox_url="$GITHUB_URL/$SINGBOX_REPO/releases/download/${singbox_latest}/sing-box-${singbox_ver}-linux-amd64.tar.gz"
        download_with_retry "$singbox_url" /tmp/singbox.tar.gz || {
            # fallback: try with v prefix in archive name
            singbox_url="$GITHUB_URL/$SINGBOX_REPO/releases/download/${singbox_latest}/sing-box-${singbox_latest}-linux-amd64.tar.gz"
            download_with_retry "$singbox_url" /tmp/singbox.tar.gz || { red "Sing-box 下载失败。"; return 1; }
        }
        tar -xzf /tmp/singbox.tar.gz -C /tmp && \
        cp "/tmp/sing-box-${singbox_ver}-linux-amd64/sing-box" "$SINGBOX_INSTALL_DIR/sing-box" && \
        chmod +x "$SINGBOX_INSTALL_DIR/sing-box" && \
        echo "$singbox_latest" > "$SINGBOX_INSTALL_DIR/version.txt" || { red "Sing-box 解压/安装失败。"; return 1; }
        rm -rf "/tmp/sing-box-${singbox_latest}-linux-amd64" /tmp/singbox.tar.gz
    else
        green "Sing-box 已是最新版本 ($singbox_latest)"
    fi
}

# =============================================================================
# 14. Systemd 服务管理与状态查询
# =============================================================================

# -----------------------------------------------------------------------------
# 确保所有 Systemd 服务模板文件都已创建
# -----------------------------------------------------------------------------
ensure_template_files() {
    local need_reload=false

    local kcp_content="[Unit]
Description=KCPTUN Instance Server (Instance %i)
After=network.target
[Service]
Type=simple
ExecStart=${KCP_INSTALL_DIR}/kcptun_server -c ${KCP_INSTALL_DIR}/kcptun_%i.json
Restart=always
RestartSec=3
[Install]
WantedBy=multi-user.target"
    local kcp_hash=$(echo "$kcp_content" | md5sum 2>/dev/null | cut -d' ' -f1)
    local existing_hash=$(md5sum "$KCPTUN_TEMPLATE_FILE" 2>/dev/null | cut -d' ' -f1)
    if [[ "$kcp_hash" != "$existing_hash" ]]; then
        echo "$kcp_content" > "$KCPTUN_TEMPLATE_FILE"; need_reload=true
    fi

    local udp_content="[Unit]
Description=UDP2RAW Instance Server (Instance %i)
After=network.target
[Service]
Type=simple
ExecStart=${UDP2RAW_INSTALL_DIR}/udp2raw --conf-file ${UDP2RAW_INSTALL_DIR}/udp2raw_%i.conf
AmbientCapabilities=CAP_NET_ADMIN CAP_NET_BIND_SERVICE CAP_NET_RAW
CapabilityBoundingSet=CAP_NET_ADMIN CAP_NET_BIND_SERVICE CAP_NET_RAW
Restart=always
RestartSec=3
[Install]
WantedBy=multi-user.target"
    local udp_hash=$(echo "$udp_content" | md5sum 2>/dev/null | cut -d' ' -f1)
    existing_hash=$(md5sum "$UDP2RAW_TEMPLATE_FILE" 2>/dev/null | cut -d' ' -f1)
    if [[ "$udp_hash" != "$existing_hash" ]]; then
        echo "$udp_content" > "$UDP2RAW_TEMPLATE_FILE"; need_reload=true
    fi

    generate_self_signed_cert

    local singbox_content="[Unit]
Description=Sing-box Service
After=network.target
[Service]
Type=simple
ExecStart=${SINGBOX_INSTALL_DIR}/sing-box run -c ${SINGBOX_INSTALL_DIR}/singbox.json
AmbientCapabilities=CAP_NET_ADMIN CAP_NET_BIND_SERVICE CAP_NET_RAW
CapabilityBoundingSet=CAP_NET_ADMIN CAP_NET_BIND_SERVICE CAP_NET_RAW
Restart=always
RestartSec=3
[Install]
WantedBy=multi-user.target"
    local singbox_hash=$(echo "$singbox_content" | md5sum 2>/dev/null | cut -d' ' -f1)
    existing_hash=$(md5sum "$SINGBOX_TEMPLATE_FILE" 2>/dev/null | cut -d' ' -f1)
    if [[ "$singbox_hash" != "$existing_hash" ]]; then
        echo "$singbox_content" > "$SINGBOX_TEMPLATE_FILE"; need_reload=true
    fi

    # 创建初始 Sing-box 基础配置 (如果不存在)
    mkdir -p "$SINGBOX_INSTALL_DIR"
    if [[ ! -f "$SINGBOX_INSTALL_DIR/singbox.json" ]]; then
        local base_config=$SINGBOX_BASE_CONFIG_TEMPLATE
        local endpoints_json='[]'
        local route_rules=$SINGBOX_NO_WARP_ROUTE_RULES

        # 自动注册 WARP WireGuard (首次安装时静默执行)
        if command -v wg &>/dev/null && [[ ! -f "$SINGBOX_INSTALL_DIR/.warp_wireguard.json" ]]; then
            register_warp_wireguard &>/dev/null || true
        fi
        if [[ -f "$SINGBOX_INSTALL_DIR/.warp_wireguard.json" ]]; then
            local wg_ep=$(apply_warp_wireguard_config) || true
            if [[ -n "$wg_ep" ]]; then
                endpoints_json=$wg_ep
                route_rules=$SINGBOX_DIRECT_ROUTE_RULES
                route_rules=${route_rules//__WARP_GEOSITE_LIST_JSON__/$WARP_GEOSITE_LIST_JSON}
            fi
        fi
        base_config=${base_config/__ENDPOINTS__/$endpoints_json}
        base_config=${base_config/__ROUTE_RULES__/$route_rules}
        echo "$base_config" > "$SINGBOX_INSTALL_DIR/singbox.json"
        log "已创建初始 Sing-box 基础配置文件: $SINGBOX_INSTALL_DIR/singbox.json"
        need_reload=true
    fi

    if [[ "$need_reload" == true ]]; then systemctl daemon-reload; fi
}

# -----------------------------------------------------------------------------
# 从配置文件中提取监听地址和端口 (用于显示状态)
# -----------------------------------------------------------------------------
get_listen_info_from_conf() {
    local conf_path=$1
    if [[ ! -f "$conf_path" ]]; then echo "配置文件不存在"; return; fi

    if [[ "$conf_path" == *".json" ]]; then
        if grep -q '"smuxver"' "$conf_path" 2>/dev/null; then
            grep -Po '(?<="listen": ")[^"]+' "$conf_path"
        elif jq -e '.inbounds[0].listen_port' "$conf_path" >/dev/null 2>&1; then
            local port=$(jq -r '.inbounds[0].listen_port // 0' "$conf_path" 2>/dev/null)
            echo "0.0.0.0:${port}"
        else
            local listen=$(jq -r '.inbounds[0].listen // "0.0.0.0"' "$conf_path" 2>/dev/null)
            local port=$(jq -r '.inbounds[0].port // 0' "$conf_path" 2>/dev/null)
            if [[ "$listen" == "null" || "$port" == "0" ]]; then echo "JSON解析错误"; else echo "${listen}:${port}"; fi
        fi
    elif [[ "$conf_path" == *".conf" ]]; then
        grep -Po '(?<=-l )[^ ]+' "$conf_path"
    fi
}

# -----------------------------------------------------------------------------
# 从配置文件中检查 WARP 是否启用
# -----------------------------------------------------------------------------
get_warp_status_from_conf() {
    local conf_path=$1
    if jq -e '.endpoints[] | select(.tag == "warp-ep" and .type == "wireguard")' "$conf_path" >/dev/null 2>&1; then echo "已启用WARP"; else echo "未启用WARP"; fi
}

# -----------------------------------------------------------------------------
# 获取单个服务的运行状态字符串 (绿色或黄色)
# -----------------------------------------------------------------------------
get_service_status_string() {
    local service_name=$1
    if systemctl is-active --quiet "$service_name"; then echo "运行中"; else echo "未运行"; fi
}

# -----------------------------------------------------------------------------
# 获取串联实例的组合状态 (颜色, 状态1, 状态2)
# -----------------------------------------------------------------------------
get_chain_status_tuple() {
    local chain_type=$1 chain_id=$2
    local service1_name="ax-singbox.service"
    service2_name="ax-udp2raw@${chain_id}.service"
    
    local s1_active=false s2_active=false status_color="yellow"
    local hy2_tag="hy2-c${chain_id#c}"
    if systemctl is-active --quiet "$service1_name" && \
       jq -e --arg tag "$hy2_tag" '.inbounds[] | select(.tag == $tag)' "$SINGBOX_INSTALL_DIR/singbox.json" >/dev/null 2>&1; then
        s1_active=true
    fi
    if systemctl is-active --quiet "$service2_name"; then s2_active=true; fi
    if $s1_active && $s2_active; then status_color="cyan"; fi
    
    echo "$status_color $(get_service_status_string "$service1_name") $(get_service_status_string "$service2_name")"
}

# -----------------------------------------------------------------------------
# 获取 3 组件串联实例的组合状态 (颜色, 状态1, 状态2, 状态3)
# -----------------------------------------------------------------------------
get_3_chain_status_tuple() {
    local chain_id=$1 # e.g., s3c1
    local ss_tag="ss-s3c${chain_id#s3c}"
    local service2_name="ax-kcptun@${chain_id}.service"        # KCPTUN
    local service3_name="ax-udp2raw@${chain_id}.service"        # UDP2RAW
    
    local s1_active=false s2_active=false s3_active=false status_color="yellow"
    # SS inbound is managed inside sing-box; check if ax-singbox.service is running and inbound exists
    if systemctl is-active --quiet ax-singbox.service && \
       jq -e --arg tag "$ss_tag" '.inbounds[] | select(.tag == $tag)' "$SINGBOX_INSTALL_DIR/singbox.json" >/dev/null 2>&1; then
        s1_active=true
    fi
    if systemctl is-active --quiet "$service2_name"; then s2_active=true; fi
    if systemctl is-active --quiet "$service3_name"; then s3_active=true; fi
    
    local s1_status="运行中"; $s1_active || s1_status="未运行"
    if $s1_active && $s2_active && $s3_active; then status_color="cyan"; fi
    
    echo "$status_color $s1_status $(get_service_status_string "$service2_name") $(get_service_status_string "$service3_name")"
}

INSTANCE_NAMES_FILE="/etc/ax-instance-names.json"

get_custom_instance_name() {
    local key=$1
    [[ ! -f "$INSTANCE_NAMES_FILE" ]] && echo "" && return
    jq -r --arg k "$key" '.[$k] // ""' "$INSTANCE_NAMES_FILE" 2>/dev/null
}

set_custom_instance_name() {
    local key=$1 name=$2; local tmp
    if [[ -f "$INSTANCE_NAMES_FILE" ]]; then
        tmp=$(jq -c --arg k "$key" --arg v "$name" '.[$k] = $v' "$INSTANCE_NAMES_FILE" 2>/dev/null)
    else
        tmp=$(jq -c -n --arg k "$key" --arg v "$name" '{($k): $v}')
    fi
    echo "$tmp" > "$INSTANCE_NAMES_FILE"
    green "实例名称已设置为: $name"
}

remove_custom_instance_name() {
    local key=$1
    [[ ! -f "$INSTANCE_NAMES_FILE" ]] && return
    local tmp=$(jq -c "del(.\"$key\")" "$INSTANCE_NAMES_FILE" 2>/dev/null)
    echo "$tmp" > "$INSTANCE_NAMES_FILE"
}

generate_instance_display_name() {
    local type=$1 id=$2
    local ip=$(get_public_ip)
    case "$type" in
        udp2raw) echo "UDP2RAW_${ip}_${id}" ;;
        kcptun) echo "KCP_${ip}_${id}" ;;
        xray_reality) echo "VLESS_${ip}_${id}" ;;
        hysteria2) echo "HY2_${ip}_${id}" ;;
        hy2_chain) echo "HY2_UDP_${ip}_${id}" ;;
        ss_3_chain_chain) echo "SS_KCP_UDP_${ip}_${id}" ;;
        *) echo "${type}_${id}" ;;
    esac
}

get_instance_display_name() {
    local type=$1 id=$2; local key="${type}_${id}"
    local custom_name=$(get_custom_instance_name "$key")
    if [[ -n "$custom_name" ]]; then echo "$custom_name"; else generate_instance_display_name "$type" "$id"; fi
}

prompt_custom_instance_name() {
    local type=$1 id=$2; local default_name=$(generate_instance_display_name "$type" "$id")
    read -p "请输入实例名称 (留空则使用默认: ${default_name}): " custom_name
    if [[ -n "$custom_name" ]]; then set_custom_instance_name "${type}_${id}" "$custom_name"; fi
}

interactive_rename_instance() {
    local type=$1 id=$2; local key="${type}_${id}"
    local current=$(get_instance_display_name "$type" "$id")
    echo "当前名称: $(cyan "$current")"
    read -p "请输入新名称 (留空恢复默认): " new_name
    if [[ -z "$new_name" ]]; then
        remove_custom_instance_name "$key"
        green "已恢复默认名称"
    else
        set_custom_instance_name "$key" "$new_name"
    fi
}

# -----------------------------------------------------------------------------
# 显示单个实例的状态行 (用于主菜单)
# -----------------------------------------------------------------------------
display_instance_status_line() {
    local type=$1 id=$2 prefix=$3; local full_id="$id"; local line; local name=$(get_instance_display_name "$type" "$id")
    case "$type" in
        "hy2_chain")
            full_id="c${id}"
            read -r color hy2_status udp_status <<< "$(get_chain_status_tuple "hy2" "$full_id")"
            local udp_info=$(get_listen_info_from_conf "$UDP2RAW_INSTALL_DIR/udp2raw_${full_id}.conf")
            local warp_status=$(get_warp_status_from_conf "$SINGBOX_INSTALL_DIR/singbox.json")
            line="$($color "${prefix}${name}:  Hysteria2 [${hy2_status}] + UDP2RAW [${udp_status}] ${udp_info} (${warp_status})")"
            ;;
        "ss_3_chain_chain")
            full_id="s3c${id}"
            read -r color s1_status s2_status s3_status <<< "$(get_3_chain_status_tuple "$full_id")"
            local udp_info=$(get_listen_info_from_conf "$UDP2RAW_INSTALL_DIR/udp2raw_${full_id}.conf")
            local warp_status=$(get_warp_status_from_conf "$SINGBOX_INSTALL_DIR/singbox.json")
            line="$($color "${prefix}${name}:  SS [${s1_status}] + KCP [${s2_status}] + UDP2RAW [${s3_status}] ${udp_info} (${warp_status})")"
            ;;
        "udp2raw"|"kcptun"|"xray_reality"|"hysteria2")
            local conf_file service_prefix title; local color_func="yellow"
            case "$type" in
                udp2raw) conf_file="$UDP2RAW_INSTALL_DIR/udp2raw_${id}.conf"; service_prefix="ax-udp2raw"; title="UDP2RAW";;
                kcptun) conf_file="$KCP_INSTALL_DIR/kcptun_${id}.json"; service_prefix="ax-kcptun"; title="KCPTUN";;
                xray_reality) conf_file="$SINGBOX_INSTALL_DIR/singbox.json"; service_prefix="ax-singbox"; title="VLESS+Reality";;
                hysteria2) conf_file="$SINGBOX_INSTALL_DIR/singbox.json"; service_prefix="ax-singbox"; title="Hysteria2";;
            esac
            local status_info=""
            if [[ "$type" == "xray_reality" || "$type" == "hysteria2" ]]; then
                local tag
                case "$type" in xray_reality) tag="vless-reality-${id}";; hysteria2) tag="hy2-${id}";; esac
                local port=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .listen_port' "$conf_file" 2>/dev/null)
                status_info="0.0.0.0:${port}"
            else
                status_info=$(get_listen_info_from_conf "$conf_file")
            fi
            local status_str=$(get_service_status_string "$service_prefix")
            local extra_info=""
            if [[ "$type" == "xray_reality" || "$type" == "hysteria2" ]]; then
                extra_info=" ($(get_warp_status_from_conf "$SINGBOX_INSTALL_DIR/singbox.json"))"
            fi
            if [[ "$status_str" == "运行中" ]]; then color_func="cyan"; fi
            line="$($color_func "${prefix}${name}:  ${title} [${status_str}] ${status_info}${extra_info}")"
            ;;
    esac
    echo -e "$line"
}

# -----------------------------------------------------------------------------
# 获取指定目录下的所有实例 ID (内部函数)
# -----------------------------------------------------------------------------
get_instances() {
    local dir=$1 pattern=$2
    find "$dir" -maxdepth 1 -name "$pattern" 2>/dev/null -printf '%f\n' | sed -E "s/.*_([a-zA-Z0-9]+)\..*/\1/" | sort -V
}

# -----------------------------------------------------------------------------
# 获取 *独立* 实例的 ID 列表 (过滤掉串联实例)
# -----------------------------------------------------------------------------
get_standalone_instances() {
    local type_lowercase=$1
    local dir="" pattern=""
    local standalone_instances=()
    
    local config_file="$SINGBOX_INSTALL_DIR/singbox.json"
    case "$type_lowercase" in
        "xray_reality")
            if [[ -f "$config_file" ]]; then
                local ids=$(jq -r '.inbounds[] | select(.type == "vless" and .tls.reality.enabled == true) | .tag | split("-")[2]' "$config_file" 2>/dev/null)
                echo "$ids"
            fi
            return
            ;;
        "hysteria2")
            if [[ -f "$config_file" ]]; then
                local ids=$(jq -r '.inbounds[] | select(.type == "hysteria2") | .tag | split("-")[1]' "$config_file" 2>/dev/null)
                echo "$ids"
            fi
            return
            ;;
        "udp2raw") dir="$UDP2RAW_INSTALL_DIR"; pattern="udp2raw_*.conf";;
        "kcptun") dir="$KCP_INSTALL_DIR"; pattern="kcptun_*.json";;
    esac

    local all_instances=$(get_instances "$dir" "$pattern")
    for i in $all_instances; do
        if [[ ! "$i" =~ ^(c|s3c)[0-9]+$ ]]; then
            standalone_instances+=($i)
        fi
    done
    echo "${standalone_instances[@]}"
}


# =============================================================================
# 15. 实例管理菜单与操作
# =============================================================================

# -----------------------------------------------------------------------------
# 管理单个独立实例的子菜单
# -----------------------------------------------------------------------------
manage_instance_menu() {
    local type=$1 id=$2 service=$3 conf=$4; local disp_name=$(get_instance_display_name "$type" "$id")
    while true; do
        clear; echo "=================================="; echo "      ${disp_name}  $(dim "(${type^^} ${id})")"; echo "=================================="
        local status_info=""
        if [[ "$type" == "xray_reality" || "$type" == "hysteria2" ]]; then
            local tag; case "$type" in xray_reality) tag="vless-reality-${id}";; hysteria2) tag="hy2-${id}";; esac
            local port=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .listen_port' "$conf" 2>/dev/null)
            status_info="0.0.0.0:${port}"
        fi
        echo "状态：$(get_service_status_string "$service") $(dim "$status_info")"
        if [[ "$type" == "xray_reality" ]]; then cyan "分享链接: $(generate_singbox_reality_link $id)"; fi
        if [[ "$type" == "hysteria2" ]]; then cyan "分享链接: $(generate_singbox_hy2_link $id)"; fi
        echo "----------------------------------"; echo "1) 启动/重启"; echo "2) 停止"; echo "3) 查看实时日志"; echo "4) 编辑配置"; echo "5) 修改实例名称"; echo "6) 查看客户端配置"; echo "99) 删除此实例"; echo "0) 返回"
        read -p "请选择 [0-6, 99]: " choice
        case $choice in
            1) log "正在启动/重启..."; systemctl restart "$service"; green "操作完成！";;
            2) log "正在停止..."; systemctl stop "$service"; green "操作完成！";;
            3) 
                log "正在实时跟踪日志... (按 Ctrl+C 仅退出日志)"
                sleep 1
                local current_trap=$(trap -p SIGINT)
                trap ':' SIGINT
                journalctl -u "$service" -f --since "1 hour ago"
                eval "$current_trap"
                ;;
            4) nano "$conf"; log "重启实例以应用配置..."; systemctl restart "$service"; green "配置已更新！";;
            5) interactive_rename_instance "$type" "$id"; read -p $'\n按任意键返回...' -n1 -s;;
            99) read -p "确认彻底删除实例 ${id}？(默认"否") [y/N]: " confirm
                if [[ "$confirm" == "y" || "$confirm" == "Y" ]]; then
                    if [[ "$type" == "xray_reality" || "$type" == "hysteria2" ]]; then
                        local tag; case "$type" in xray_reality) tag="vless-reality-${id}";; hysteria2) tag="hy2-${id}";; esac
                        remove_singbox_inbound "$tag"
                    else
                        systemctl stop "$service"; systemctl disable "$service" >/dev/null 2>&1; rm -f "$conf"
                    fi
                    remove_custom_instance_name "${type}_${id}"; systemctl daemon-reload; green "实例 ${id} 已删除！"; break
                fi;;
             6) clear; echo "--- ${type^^} 客户端配置 (实例 $id) ---"
                case "$type" in
                    "udp2raw") view_udp2raw_client_config "$id" ;;
                    "kcptun") view_kcptun_client_config "$id" ;;
                    "xray_reality") cyan "分享链接: $(generate_singbox_reality_link "$id")" ;;
                    "hysteria2") cyan "分享链接: $(generate_singbox_hy2_link "$id")" ;;
                esac
               read -p $'\n按任意键返回...' -n1 -s;;
            0) break;; *) red "无效输入";;
        esac
        [[ "$choice" == "1" || "$choice" == "2" || "$choice" == "4" ]] && read -p $'\n按任意键返回...' -n1 -s
    done
}

# -----------------------------------------------------------------------------
# 创建一个新的独立实例 (Hysteria2, UDP2RAW, KCPTUN)
# -----------------------------------------------------------------------------
create_new_instance() {
    local type=$1; local next_id; local INSTALL_DIR SERVICE_PREFIX FILE_EXT TITLE CONFIG_TEMPLATE SYSTEMD_SERVICE_NAME
    declare -A replacements

    case "$type" in
        udp2raw) TITLE="UDP2RAW"; INSTALL_DIR="$UDP2RAW_INSTALL_DIR"; SERVICE_PREFIX="udp2raw"; SYSTEMD_SERVICE_NAME="ax-udp2raw"; FILE_EXT="conf"; CONFIG_TEMPLATE="$UDP2RAW_CONFIG_TEMPLATE" 
            log "启动一个新的 ${TITLE} 实例..."; next_id=$(find_next_available_id "$type")
            green "新实例将被创建为: ax-${SYSTEMD_SERVICE_NAME}@${next_id}.service"
            prompt_custom_instance_name "$type" "$next_id"
            read -p "请输入监听地址 (默认: $DEFAULT_LISTEN_ADDR): " listen_addr_input; listen_addr=${listen_addr_input:-$DEFAULT_LISTEN_ADDR}
            read_valid_port "请输入监听端口 (留空则随机生成): " listen_port true
            replacements["__LISTEN_ADDR__"]="${listen_addr}:${listen_port}"
            read -p "请输入目标地址 (默认: $DEFAULT_TARGET_ADDR): " target_host; target_host=${target_host:-$DEFAULT_TARGET_ADDR}
            read_valid_port "请输入目标端口 (留空则随机生成): " target_port true
            replacements["__TARGET_ADDR__"]="${target_host}:${target_port}"
            
            # 收集UDP2RAW配置参数
            local udp_params=$(collect_udp2raw_params)
            IFS='|' read -r raw_mode cipher_mode auth_mode <<< "$udp_params"
            replacements["__RAW_MODE__"]="$raw_mode"
            replacements["__CIPHER_MODE__"]="$cipher_mode"
            replacements["__AUTH_MODE__"]="$auth_mode"
            
            # 生成密码
            local password=$(handle_password_input "$type"); replacements["__PASSWORD__"]="$password"
            ;;
            
        kcptun) TITLE="KCPTUN"; INSTALL_DIR="$KCP_INSTALL_DIR"; SERVICE_PREFIX="kcptun"; SYSTEMD_SERVICE_NAME="ax-kcptun"; FILE_EXT="json"; CONFIG_TEMPLATE="$KCPTUN_CONFIG_JSON_TEMPLATE" 
            log "启动一个新的 ${TITLE} 实例..."; next_id=$(find_next_available_id "$type")
            green "新实例将被创建为: ax-${SYSTEMD_SERVICE_NAME}@${next_id}.service"
            prompt_custom_instance_name "$type" "$next_id"
            read -p "请输入监听地址 (默认: $DEFAULT_LISTEN_ADDR): " listen_addr_input; listen_addr=${listen_addr_input:-$DEFAULT_LISTEN_ADDR}
            read_valid_port "请输入监听端口 (留空则随机生成): " listen_port true
            replacements["__LISTEN__"]="${listen_addr}:${listen_port}"
            read -p "请输入目标地址 (默认: $DEFAULT_TARGET_ADDR): " target_host; target_host=${target_host:-$DEFAULT_TARGET_ADDR}
            read_valid_port "请输入目标端口 (留空则随机生成): " target_port true
            replacements["__TARGET__"]="${target_host}:${target_port}"
            
            # 收集KCPTUN配置参数
            local kcp_params=$(collect_kcptun_params)
            IFS='|' read -r mode crypt tcp_enabled mtu sndwnd rcvwnd <<< "$kcp_params"
            replacements["__MODE__"]="$mode"
            replacements["__CRYPT__"]="$crypt"
            replacements["__TCP__"]="$tcp_enabled"
            replacements["__MTU__"]="$mtu"
            replacements["__SNDWND__"]="$sndwnd"
            replacements["__RCVWND__"]="$rcvwnd"
            replacements["__NOCOMP__"]="true"
            
            # 生成密码
            local password=$(handle_password_input "$type"); replacements["__KEY__"]="$password"
            ;;
            
        *) red "内部错误: 无效的实例类型 '$type'"; return 1 ;;
    esac

    log "生成配置文件..."; local temp_config="$CONFIG_TEMPLATE"; local conf_path="${INSTALL_DIR}/${SERVICE_PREFIX}_${next_id}.${FILE_EXT}"
    for placeholder in "${!replacements[@]}"; do temp_config="${temp_config//${placeholder}/${replacements[${placeholder}]}}"; done
    echo "$temp_config" > "$conf_path"

    sync; log "启动服务..."; systemctl enable --now "${SYSTEMD_SERVICE_NAME}@${next_id}.service"; sleep 1; green "实例 ${next_id} 已启动！"; echo
    case "$type" in
        udp2raw) view_udp2raw_client_config "$next_id" ;;
        kcptun) view_kcptun_client_config "$next_id" ;;
    esac
}

# -----------------------------------------------------------------------------
# 添加一个新的 Sing-box inbound (Reality, Shadowsocks, Hysteria2)
# -----------------------------------------------------------------------------
# 添加一个新的 Sing-box inbound
# -----------------------------------------------------------------------------
add_singbox_inbound() {
    local type=$1; local next_id;
    next_id=$(find_next_available_id "singbox")
    prompt_custom_instance_name "$type" "$next_id"
    
    local inbound_json=""
    local tag=""

    if [[ "$type" == "xray_reality" ]]; then
        tag="vless-reality-${next_id}"
        log "添加一个新的 VLESS+Reality inbound, tag: $tag"
        
        local listen_port; read_valid_port "请输入监听端口 (留空则随机): " listen_port true
        
        local uuid=$(generate_strong_password)
        
        log "正在生成 Reality 密钥对..."
        local tmp_key=$("$SINGBOX_INSTALL_DIR/sing-box" generate reality-keypair 2>/dev/null)
        if [[ -z "$tmp_key" ]]; then
            red "错误: sing-box generate reality-keypair 失败！请确保 sing-box 已正确安装。"
            return 1
        fi
        local private_key=$(echo "$tmp_key" | grep "PrivateKey" | awk '{print $2}')
        local public_key=$(echo "$tmp_key" | grep "PublicKey" | awk '{print $2}')

        if [[ -z "$private_key" || -z "$public_key" ]]; then
            red "错误: 无法解析 Reality 密钥对！"
            log "Sing-box 命令输出 (Debug): $tmp_key"
            return 1
        fi

        save_reality_keypair "vless-reality-${next_id}" "$private_key" "$public_key"

        local short_id=$(openssl rand -hex 8)
        
        inbound_json=$SINGBOX_VLESS_REALITY_TEMPLATE
        inbound_json=${inbound_json/__ID__/$next_id}
        inbound_json=${inbound_json/__LISTEN_PORT__/$listen_port}
        inbound_json=${inbound_json/__UUID__/$uuid}
        inbound_json=${inbound_json/__REALITY_FLOW__/$SINGBOX_REALITY_DEFAULT_FLOW}
        inbound_json=${inbound_json/__SNI__/$SINGBOX_REALITY_DEFAULT_SNI}
        inbound_json=${inbound_json/__PRIVATE_KEY__/$private_key}
        inbound_json=${inbound_json/__SHORT_ID__/$short_id}
        
    elif [[ "$type" == "hysteria2" ]]; then
        tag="hy2-${next_id}"
        log "添加一个新的 Hysteria2 inbound, tag: $tag"
        
        local listen_port; read_valid_port "请输入监听端口 (留空则随机): " listen_port true
        local hy2_password=$(handle_password_input "hysteria2")
        
        inbound_json=$SINGBOX_HYSTERIA2_TEMPLATE
        inbound_json=${inbound_json/__ID__/$next_id}
        inbound_json=${inbound_json/__LISTEN_PORT__/$listen_port}
        inbound_json=${inbound_json/__PASSWORD__/$hy2_password}
        inbound_json=${inbound_json/__SNI__/$HY2_SNI}
        inbound_json=${inbound_json/__KEY_PATH__/$HY2_KEY_PATH}
        inbound_json=${inbound_json/__CERT_PATH__/$HY2_CERT_PATH}
    fi

    if [[ -z "$inbound_json" ]]; then red "错误: 未知的 inbound 类型 '$type'"; return 1; fi

    local config_file="$SINGBOX_INSTALL_DIR/singbox.json"
    if [[ ! -f "$config_file" ]]; then
        red "错误: 基础配置文件 $config_file 不存在！请先安装 Sing-box。"
        return 1
    fi

    log "将 inbound 添加到 singbox.json..."
    local tmpfile=$(mktemp)
    jq --argjson inbound "$inbound_json" '.inbounds += [$inbound]' "$config_file" > "$tmpfile" && mv "$tmpfile" "$config_file"

    sync; log "重启 Sing-box 服务..."; systemctl restart ax-singbox.service; sleep 1;
    if ! systemctl is-active --quiet ax-singbox.service; then
        red "Sing-box 重启失败！请检查配置或日志。"
        log "journalctl -u ax-singbox.service -n 20"
        return 1
    else
        green "Inbound '$tag' 已添加！Sing-box 运行正常。"; echo
        if [[ "$type" == "xray_reality" ]]; then
            cyan "分享链接: $(generate_singbox_reality_link "$next_id")"
        elif [[ "$type" == "hysteria2" ]]; then
            cyan "分享链接: $(generate_singbox_hy2_link "$next_id")"
        fi
    fi
}

# -----------------------------------------------------------------------------
# 从 singbox.json 中移除一个 inbound (通过 tag)
# -----------------------------------------------------------------------------
remove_singbox_inbound() {
    local tag=$1
    local config_file="$SINGBOX_INSTALL_DIR/singbox.json"
    if [[ ! -f "$config_file" ]]; then red "配置文件不存在"; return 1; fi
    local tmpfile=$(mktemp)
    jq --arg tag "$tag" 'del(.inbounds[] | select(.tag == $tag))' "$config_file" > "$tmpfile" && mv "$tmpfile" "$config_file"
    systemctl restart ax-singbox.service
    green "Inbound '$tag' 已移除。"
}

# =============================================================================
# 16. 客户端配置与订阅链接生成
# =============================================================================

# -----------------------------------------------------------------------------
# 生成 Hysteria2 订阅链接
# -----------------------------------------------------------------------------
# -----------------------------------------------------------------------------
# Reality 密钥存储文件路径
# -----------------------------------------------------------------------------
SINGBOX_REALITY_KEYS_FILE="$SINGBOX_INSTALL_DIR/.reality_keys.json"

# -----------------------------------------------------------------------------
# 保存 Reality 密钥对
# -----------------------------------------------------------------------------
save_reality_keypair() {
    local tag=$1 private_key=$2 public_key=$3
    local keys_file="$SINGBOX_REALITY_KEYS_FILE"
    mkdir -p "$(dirname "$keys_file")"
    if [[ -f "$keys_file" ]]; then
        local tmp=$(mktemp)
        jq --arg tag "$tag" --arg priv "$private_key" --arg pub "$public_key" \
            '.[$tag] = {"private_key": $priv, "public_key": $pub}' "$keys_file" > "$tmp" && mv "$tmp" "$keys_file"
    else
        echo "{\"$tag\": {\"private_key\": \"$private_key\", \"public_key\": \"$public_key\"}}" > "$keys_file"
    fi
    chmod 600 "$keys_file"
}

# -----------------------------------------------------------------------------
# 获取 Reality 公钥 (从存储文件读取)
# -----------------------------------------------------------------------------
get_reality_public_key() {
    local tag=$1
    local keys_file="$SINGBOX_REALITY_KEYS_FILE"
    if [[ -f "$keys_file" ]]; then
        jq -r --arg tag "$tag" '.[$tag].public_key' "$keys_file" 2>/dev/null
    fi
}

# -----------------------------------------------------------------------------
# 生成 Sing-box VLESS+Reality 分享链接
# -----------------------------------------------------------------------------
generate_singbox_reality_link() {
    local id=$1; local tag="vless-reality-${id}"
    local ip=$(get_public_ip)
    local conf="$SINGBOX_INSTALL_DIR/singbox.json"
    if [[ ! -s "$conf" ]]; then echo "N/A"; return; fi
    local port=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .listen_port' "$conf")
    local uuid=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .users[0].uuid' "$conf")
    local sni=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .tls.server_name' "$conf")
    local sid=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .tls.reality.short_id[0]' "$conf")
    local flow=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .users[0].flow' "$conf")
    if [[ -z "$port" || "$port" == "null" || -z "$uuid" || "$uuid" == "null" ]]; then echo "N/A"; return; fi
    local pbk=$(get_reality_public_key "$tag")
    if [[ -z "$pbk" || "$pbk" == "null" ]]; then pbk="MISSING_KEY"; fi
    local link="vless://${uuid}@${ip}:${port}?type=tcp&security=reality&sni=${sni}&pbk=${pbk}&flow=${flow}&sid=${sid}&fp=chrome#Singbox_Reality_${ip}_${id}"
    echo "$link"
}

# -----------------------------------------------------------------------------
# 生成 Sing-box Hysteria2 分享链接
# -----------------------------------------------------------------------------
generate_singbox_hy2_link() {
    local id=$1; local tag="hy2-${id}"
    local ip=$(get_public_ip)
    local conf="$SINGBOX_INSTALL_DIR/singbox.json"
    if [[ ! -s "$conf" ]]; then echo "N/A"; return; fi
    local port=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .listen_port' "$conf")
    local password=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .users[0].password' "$conf")
    local sni=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .tls.server_name' "$conf")
    if [[ -z "$port" || "$port" == "null" || -z "$password" || "$password" == "null" ]]; then echo "N/A"; return; fi
    local link="hysteria2://${password}@${ip}:${port}?sni=${sni}&insecure=1#Singbox_HY2_${ip}_${id}"
    echo "$link"
}

# -----------------------------------------------------------------------------
# 查看 UDP2RAW 客户端配置
# -----------------------------------------------------------------------------
view_udp2raw_client_config(){
    local id=$1; local conf="$UDP2RAW_INSTALL_DIR/udp2raw_${id}.conf"; if [[ ! -s "$conf" ]]; then red "错误: 未找到实例 $id 的配置文件或文件为空。"; return; fi
    local ip=$(get_public_ip); local port=$(get_listen_info_from_conf "$conf" | awk -F':' '{print $NF}'); local password=$(grep -Po '(?<=-k )[^ ]+' "$conf")
    
    cyan "--- UDP2RAW 实例 ${id} 客户端配置 ---";  echo
    green "${UDP2RAW_CLIENT_BASE_ARGS} -r ${ip}:${port} -l ${CLIENT_UDP2RAW_LISTEN_ADDR} -k ${password}"
}

# -----------------------------------------------------------------------------
# 查看 KCPTUN 客户端配置
# -----------------------------------------------------------------------------
view_kcptun_client_config(){
    local id=$1; local conf="$KCP_INSTALL_DIR/kcptun_${id}.json"; if [[ ! -s "$conf" ]]; then red "错误: 未找到实例 $id 的配置文件或文件为空。"; return; fi
    if ! command -v jq &>/dev/null; then red "错误: jq 未安装，无法解析配置。"; return; fi
    local ip=$(get_public_ip); local server_listen=$(jq -r '.listen' "$conf"); local server_port=$(echo "$server_listen" | awk -F':' '{print $NF}'); cyan "--- KCPTUN 实例 ${id} 客户端配置 ---"; echo
    yellow "方法一: 使用 JSON 配置文件 (推荐)"; yellow "将以下内容保存为客户端的 config.json (本地监听地址 ${CLIENT_KCPTUN_LISTEN_ADDR} 可自行修改):"; green "$(jq --arg listen "${CLIENT_KCPTUN_LISTEN_ADDR}" --arg target "${ip}:${server_port}" '.listen = $listen | .target = $target' "$conf")"; echo
    yellow "方法二: 使用命令行参数"; yellow "在客户端使用以下命令行参数 (本地监听地址 ${CLIENT_KCPTUN_LISTEN_ADDR} 可自行修改):";local args="--listen ${CLIENT_KCPTUN_LISTEN_ADDR} --target ${ip}:${server_port}"
    for key in $(jq -r 'keys_unsorted | .[]' "$conf"); do if [[ "$key" != "listen" && "$key" != "target" ]]; then local value=$(jq -r --arg k "$key" '.[$k]' "$conf"); args+=" --${key} ${value}"; fi; done; green "$args"; echo
}

# =============================================================================
# 17. 组件串联实例管理 (SS+KCP+UDP)
# =============================================================================

# [NEW] 获取 3 组件串联实例ID列表 (ss_3_chain)
# -----------------------------------------------------------------------------
# 获取 3 组件串联实例ID列表 (ss_3_chain)
# -----------------------------------------------------------------------------
get_chain_instances_3() {
    local instances1=$(jq -r '.inbounds[] | select(.type == "shadowsocks") | .tag | split("-")[1] | select(startswith("s3c")) | .[3:]' "$SINGBOX_INSTALL_DIR/singbox.json" 2>/dev/null)
    local instances2=$(ls -1 "$KCP_INSTALL_DIR"/kcptun_s3c*.json 2>/dev/null | sed -E 's/.*_s3c([0-9]+).*/\1/')
    local instances3=$(ls -1 "$UDP2RAW_INSTALL_DIR"/udp2raw_s3c*.conf 2>/dev/null | sed -E 's/.*_s3c([0-9]+).*/\1/')
    echo "$instances1 $instances2 $instances3" | tr ' ' '\n' | sort -un
}

# -----------------------------------------------------------------------------
# 查看 3 组件串联实例的客户端配置
# -----------------------------------------------------------------------------
view_chain_client_config_3() {
    local id_num=$1
    local id="s3c${id_num}"
    local ss_tag="ss-${id}"
    local config_file="$SINGBOX_INSTALL_DIR/singbox.json"
    local kcptun_conf_path="$KCP_INSTALL_DIR/kcptun_${id}.json"
    local udp2raw_conf_path="$UDP2RAW_INSTALL_DIR/udp2raw_${id}.conf"
    
    if [[ ! -f "$kcptun_conf_path" || ! -f "$udp2raw_conf_path" ]]; then
        red "串联实例 ${id} 的配置文件不完整。"; return
    fi
    
    local ss_method=$(jq -r --arg tag "$ss_tag" '.inbounds[] | select(.tag == $tag) | .method' "$config_file" 2>/dev/null)
    local ss_password=$(jq -r --arg tag "$ss_tag" '.inbounds[] | select(.tag == $tag) | .password' "$config_file" 2>/dev/null)
    if [[ -z "$ss_method" || "$ss_method" == "null" ]]; then red "SS inbound $ss_tag 未在 singbox.json 中找到。"; return; fi
    
    local ip=$(get_public_ip)
    local udp2raw_port=$(get_listen_info_from_conf "$udp2raw_conf_path" | awk -F':' '{print $NF}')
    local udp2raw_password=$(grep -Po '(?<=-k )[^ ]+' "$udp2raw_conf_path")
    local kcptun_password=$(jq -r '.key' "$kcptun_conf_path")
    
    cyan "--- SS+KCP+UDP 实例 ${id} 客户端配置 ---"; echo
    
    yellow "步骤 1: 运行 UDP2RAW (客户端)"
    yellow " (它会监听 ${CLIENT_SS_3_CHAIN_KCP_TARGET}, 作为 KCPTUN 的目标)"
    local client_args_udp2raw="${UDP2RAW_CLIENT_BASE_ARGS} -r ${ip}:${udp2raw_port} -l ${CLIENT_SS_3_CHAIN_KCP_TARGET} -k ${udp2raw_password}"
    green "$client_args_udp2raw"; echo
    
    yellow "步骤 2: 运行 KCPTUN (客户端)"
    yellow " (它会监听 ${CLIENT_SS_3_CHAIN_SS_TARGET}, 作为 SS 的目标)"

    local kcp_args="--listen ${CLIENT_SS_3_CHAIN_SS_TARGET} --target ${CLIENT_SS_3_CHAIN_KCP_TARGET}"
    # 解析 JSON 并将所有其他键附加为参数
    for key in $(jq -r 'keys_unsorted | .[]' "$kcptun_conf_path"); do
        if [[ "$key" != "listen" && "$key" != "target" ]]; then
            local value=$(jq -r --arg k "$key" '.[$k]' "$kcptun_conf_path")
            kcp_args+=" --${key} ${value}"
        fi
    done
    green "$kcp_args"; echo
    
    yellow "步骤 3: SS 客户端配置 (指向本地 KCPTUN)"
    local ss_user_info=$(echo -n "${ss_method}:${ss_password}" | base64 | tr -d '\n' | sed 's/=*$//')
    local ss_host=$(echo "$CLIENT_SS_3_CHAIN_SS_TARGET" | cut -d: -f1)
    local ss_port=$(echo "$CLIENT_SS_3_CHAIN_SS_TARGET" | cut -d: -f2)
    
    # [修改点] 统一命名格式为 Chain_ss_kcp_... +UDP2RAW
    # [New] 提取 KCPTUN 参数并添加到 URL 参数
    local kcp_mode=$(jq -r '.mode' "$kcptun_conf_path")
    local kcp_crypt=$(jq -r '.crypt' "$kcptun_conf_path")
    local kcp_nocomp=$(jq -r '.nocomp' "$kcptun_conf_path")

    local sub_link="ss://${ss_user_info}@${ss_host}:${ss_port}/?kcp_mode=${kcp_mode}&kcp_crypt=${kcp_crypt}&kcp_nocomp=${kcp_nocomp}#Chain_ss_kcp_${ip}_${id}+UDP2RAW"
    green "$sub_link"; echo

    echo
    yellow "[SS+KCPTUN+UDP2RAW] 合并订阅链接 (复制以下整行):"
    local ss_chain_clean="ss://${ss_user_info}@${ss_host}:${ss_port}/?kcp_mode=${kcp_mode}&kcp_crypt=${kcp_crypt}&kcp_nocomp=${kcp_nocomp}"
    local kcp_chain_link="kcptun://${kcp_args}"
    local udp_chain_link="udp2raw://${client_args_udp2raw}"
    local chain_name="chian_ss+kcp+udp_${ip}_${id_num}"
    green "CHAIN://[${ss_chain_clean} && ${kcp_chain_link} && ${udp_chain_link}]#${chain_name}"
    echo
}

# -----------------------------------------------------------------------------
# 启动一个新的 3 组件串联实例 (SS+KCP+UDP)
# -----------------------------------------------------------------------------
start_new_chain_instance_3() {
    local i=1
    while true; do
        local tag="ss-s3c${i}"
        if ! jq -e --arg tag "$tag" '.inbounds[] | select(.tag == $tag)' "$SINGBOX_INSTALL_DIR/singbox.json" >/dev/null 2>&1; then break; fi
        i=$((i + 1))
    done
    
    local chain_id="s3c${i}"
    log "启动一个新的 SS+KCP+UDP 串联实例..."
    green "新串联实例 #${i} (SS + KCPTUN + UDP2RAW 三层串联)"
    prompt_custom_instance_name "ss_3_chain_chain" "$i"
    
    read_valid_port "请输入UDP2RAW对外端口 (留空则随机): " udp2raw_listen_port true
    green "已指定对外端口 (UDP2RAW): $udp2raw_listen_port"
    
    read_valid_port "请输入KCPTUN内联端口 (UDP2RAW->KCPTUN) (留空则随机生成): " kcptun_listen_port true
    
    read_valid_port "请输入SS内联端口 (KCPTUN->SS) (留空则随机生成): " ss_listen_port true
    
    cyan "--- SS (Sing-box) 配置 ---"
    echo "Shadowsocks 加密方式选项:"
    echo "1) 2022-blake3-aes-256-gcm (推荐)"
    echo "2) 2022-blake3-aes-128-gcm"
    echo "3) 2022-blake3-chacha20-poly1305"
    echo "4) aes-256-gcm"
    echo "5) aes-128-gcm"
    echo "6) chacha20-poly1305"
    read -p "请选择加密方式 (默认 1): " ss_method_choice
    ss_method_choice=${ss_method_choice:-1}
    
    local ss_method=""
    case $ss_method_choice in
        1) ss_method="2022-blake3-aes-256-gcm" ;;
        2) ss_method="2022-blake3-aes-128-gcm" ;;
        3) ss_method="2022-blake3-chacha20-poly1305" ;;
        4) ss_method="aes-256-gcm" ;;
        5) ss_method="aes-128-gcm" ;;
        6) ss_method="chacha20-poly1305" ;;
        *) ss_method="2022-blake3-aes-256-gcm" ;;
    esac
    
    cyan "--- KCPTUN 配置 ---"
    local kcp_params=$(collect_kcptun_params)
    IFS='|' read -r kcp_mode kcp_crypt kcp_tcp mtu sndwnd rcvwnd <<< "$kcp_params"
    
    cyan "--- UDP2RAW 配置 ---"
    local udp_params=$(collect_udp2raw_params)
    IFS='|' read -r udp_raw_mode udp_cipher_mode udp_auth_mode <<< "$udp_params"
    
    log "正在自动生成所有密码..."
    local udp2raw_password=$(generate_strong_password)
    green "已自动生成 UDP2RAW 密码: $udp2raw_password"
    
    local kcptun_password=$(generate_strong_password)
    green "已自动生成 KCPTUN 密码: $kcptun_password"

    if ! command -v openssl &>/dev/null; then 
        red "错误: openssl 未安装, 无法生成 SS 密钥！"; return 1; 
    fi
    local ss_password=$(openssl rand -base64 32)
    green "已自动生成 SS-2022 Base64 密钥: $ss_password"
    
    # 创建 SS inbound in singbox.json
    local ss_inbound=$SINGBOX_SHADOWSOCKS_TEMPLATE
    ss_inbound=${ss_inbound/__ID__/s3c${i}}
    ss_inbound=${ss_inbound/__LISTEN_PORT__/$ss_listen_port}
    ss_inbound=${ss_inbound/__SS_METHOD__/$ss_method}
    ss_inbound=${ss_inbound/__SS_PASSWORD__/$ss_password}
    
    local tmpfile=$(mktemp)
    jq --argjson inbound "$ss_inbound" '.inbounds += [$inbound]' "$SINGBOX_INSTALL_DIR/singbox.json" > "$tmpfile" && mv "$tmpfile" "$SINGBOX_INSTALL_DIR/singbox.json"
    
    local kcp_config="$KCPTUN_CONFIG_JSON_TEMPLATE"
    kcp_config=${kcp_config/__LISTEN__/127.0.0.1:${kcptun_listen_port}}
    kcp_config=${kcp_config/__TARGET__/127.0.0.1:${ss_listen_port}}
    kcp_config=${kcp_config/__KEY__/$kcptun_password}
    kcp_config=${kcp_config/__MODE__/$kcp_mode}
    kcp_config=${kcp_config/__CRYPT__/$kcp_crypt}
    kcp_config=${kcp_config/__TCP__/$kcp_tcp}
    kcp_config=${kcp_config/__MTU__/$mtu}
    kcp_config=${kcp_config/__SNDWND__/$sndwnd}
    kcp_config=${kcp_config/__RCVWND__/$rcvwnd}
    kcp_config=${kcp_config/__NOCOMP__/true}
    local kcp_conf_path="$KCP_INSTALL_DIR/kcptun_${chain_id}.json"
    
    local udp_config="${UDP2RAW_CONFIG_TEMPLATE}"
    udp_config="${udp_config//__LISTEN_ADDR__/0.0.0.0:${udp2raw_listen_port}}"
    udp_config="${udp_config//__TARGET_ADDR__/127.0.0.1:${kcptun_listen_port}}"
    udp_config="${udp_config//__PASSWORD__/${udp2raw_password}}"
    udp_config="${udp_config//__RAW_MODE__/${udp_raw_mode}}"
    udp_config="${udp_config//__CIPHER_MODE__/${udp_cipher_mode}}"
    udp_config="${udp_config//__AUTH_MODE__/${udp_auth_mode}}"
    local udp_conf_path="$UDP2RAW_INSTALL_DIR/udp2raw_${chain_id}.conf"
    
    log "生成配置文件..."
    echo "$kcp_config" > "$kcp_conf_path"
    echo "$udp_config" > "$udp_conf_path"
    
    sync; log "启动串联服务...";
    systemctl restart ax-singbox.service
    systemctl enable --now "ax-kcptun@${chain_id}.service"
    systemctl enable --now "ax-udp2raw@${chain_id}.service"
    
    sleep 1; green "串联实例 ${chain_id} 已启动！"; echo
    view_chain_client_config_3 "$i"
}

# -----------------------------------------------------------------------------
# [NEW] 管理 3 组件串联实例
# -----------------------------------------------------------------------------
manage_chain_instance_3() {
    local id_num=$1
    local manage_id="s3c${id_num}"
    local manage_type="ss_3_chain_chain"
    local disp_name=$(get_instance_display_name "$manage_type" "$id_num")
    
    local service1_full="ax-singbox.service" # SS (managed inside sing-box)
    local service2_full="ax-kcptun@${manage_id}.service"        # KCP
    local service3_full="ax-udp2raw@${manage_id}.service"        # UDP2RAW
    
    local conf1_path="$SINGBOX_INSTALL_DIR/singbox.json"
    local conf2_path="$KCP_INSTALL_DIR/kcptun_${manage_id}.json"
    local conf3_path="$UDP2RAW_INSTALL_DIR/udp2raw_${manage_id}.conf"
    
    while true; do
        clear; echo "=================================="; echo "     ${disp_name}  $(dim "(${manage_id})")"; echo "=================================="
        read -r color s1_status s2_status s3_status <<< "$(get_3_chain_status_tuple "$manage_id")"
        local udp2raw_info=$(get_listen_info_from_conf "$conf3_path")
        
        $color "状态: SS [${s1_status}] + KCP [${s2_status}] + UDP2RAW [${s3_status}] $(dim "$udp2raw_info")"

        echo "----------------------------------"; echo "1) 启动/重启此串联"; echo "2) 停止此串联"; echo "3) 查看客户端配置"; echo "4) 查看 Sing-box (SS) 日志"; echo "5) 查看 KCPTUN 日志"; echo "6) 查看 UDP2RAW 日志"; echo "7) 编辑 Sing-box 配置文件"; echo "8) 编辑 KCPTUN 配置文件"; echo "9) 编辑 UDP2RAW 配置文件"; echo "10) 修改实例名称"; echo "99) 彻底删除此串联"; echo "0) 返回"
        read -p "请选择: " manage_choice
        case $manage_choice in
            1) log "重启串联..."; systemctl restart ax-singbox.service "$service2_full" "$service3_full";;
            2) log "停止串联..."; systemctl stop ax-singbox.service "$service2_full" "$service3_full";;
            3) view_chain_client_config_3 "$id_num"; read -p $'\n按任意键返回...' -n1 -s;;
            4) log "正在实时跟踪 Sing-box (SS) 日志... (按 Ctrl+C 仅退出日志)"; local ct=$(trap -p SIGINT); trap ':' SIGINT; journalctl -u ax-singbox.service -f; eval "$ct";;
            5) log "正在实时跟踪 KCPTUN 日志... (按 Ctrl+C 仅退出日志)"; local ct=$(trap -p SIGINT); trap ':' SIGINT; journalctl -u "$service2_full" -f; eval "$ct";;
            6) log "正在实时跟踪 UDP2RAW 日志... (按 Ctrl+C 仅退出日志)"; local ct=$(trap -p SIGINT); trap ':' SIGINT; journalctl -u "$service3_full" -f; eval "$ct";;
            7) nano "$conf1_path"; systemctl restart ax-singbox.service;;
            8) nano "$conf2_path"; systemctl restart "$service2_full";;
            9) nano "$conf3_path"; systemctl restart "$service3_full";;
            10) interactive_rename_instance "$manage_type" "$id_num"; read -p $'\n按任意键返回...' -n1 -s;;
            99) read -p "确认删除串联实例 ${manage_id}？(默认"否") [y/N]: " del_confirm; if [[ "$del_confirm" == "y" ]]; then 
                log "删除串联..."; 
                remove_singbox_inbound "ss-${manage_id}"
                systemctl stop "$service2_full" "$service3_full"; 
                systemctl disable "$service2_full" "$service3_full" >/dev/null 2>&1; 
                rm -f "$conf2_path" "$conf3_path"; 
                remove_custom_instance_name "${manage_type}_${id_num}"
                systemctl daemon-reload; green "已删除。"; break; 
                fi;;
            0) break;; *) red "无效输入";;
        esac
        [[ "$manage_choice" == "1" || "$manage_choice" == "2" || "$manage_choice" == "7" || "$manage_choice" == "8" || "$manage_choice" == "9" ]] && read -p $'\n按任意键返回...' -n1 -s
    done
}


# =============================================================================
# 18. 组件串联实例管理 (Hysteria2 + UDP2RAW)
# =============================================================================

# -----------------------------------------------------------------------------
# 获取 2 组件串联实例ID列表 (hy2 或 vless)
# -----------------------------------------------------------------------------
get_chain_instances() {
    local chain_type=$1
    local instances1="" instances2=""
    if [[ "$chain_type" == "hy2" ]]; then
        instances1=$(jq -r '.inbounds[] | select(.tag | startswith("hy2-c")) | .tag | split("-")[1]' "$SINGBOX_INSTALL_DIR/singbox.json" 2>/dev/null)
        instances2=$(ls -1 "$UDP2RAW_INSTALL_DIR"/udp2raw_c*.conf 2>/dev/null | sed -E 's/.*_c([0-9]+).*/\1/')
    fi
    echo "$instances1 $instances2" | tr ' ' '\n' | sort -un
}

# -----------------------------------------------------------------------------
# 查看 2 组件串联实例的客户端配置
# -----------------------------------------------------------------------------
view_chain_client_config() {
    local chain_type=$1 id_num=$2
    local id_prefix="" client_listen_addr="" title=""
    if [[ "$chain_type" == "hy2" ]]; then
        id_prefix="c"; title="Hysteria2"; client_listen_addr="$CLIENT_UDP2RAW_LISTEN_ADDR"
    else
        return
    fi
    local id="${id_prefix}${id_num}"
    local udp2raw_conf="$UDP2RAW_INSTALL_DIR/udp2raw_${id}.conf"
    if [[ ! -f "$udp2raw_conf" ]]; then red "串联实例 ${id} 的 UDP2RAW 配置文件不完整。"; return; fi
    
    local ip=$(get_public_ip)
    local udp2raw_port=$(get_listen_info_from_conf "$udp2raw_conf" | awk -F':' '{print $NF}')
    local udp2raw_password=$(grep -Po '(?<=-k )[^ ]+' "$udp2raw_conf")
    
    local client_args="${UDP2RAW_CLIENT_BASE_ARGS} -r ${ip}:${udp2raw_port} -l ${client_listen_addr} -k ${udp2raw_password}"
    local client_udp2raw_host=$(echo "$client_listen_addr" | cut -d: -f1)
    local client_udp2raw_port=$(echo "$client_listen_addr" | cut -d: -f2)
    local sub_link=""
    local display_title=""
    local host_label=$ip
    local server_addr=$ip

    if [[ "$chain_type" == "hy2" ]]; then
        display_title="[hy2+UDP2RAW]"
        local tag="hy2-c${id_num}"
        local hy2_password=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .users[0].password' "$SINGBOX_INSTALL_DIR/singbox.json" 2>/dev/null)
        
        local sni=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .tls.server_name // empty' "$SINGBOX_INSTALL_DIR/singbox.json" 2>/dev/null)
        local cert_path=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .tls.certificate_path // empty' "$SINGBOX_INSTALL_DIR/singbox.json" 2>/dev/null)
        local insecure_flag=0
        
        if [[ "$sni" == "$HY2_SNI" || -z "$sni" ]]; then
            insecure_flag=$HY2_CLIENT_INSECURE
            sni="$HY2_SNI"
        fi
        
        if [[ -n "$cert_path" && "$cert_path" == *"$AX_CERT_DIR"* ]]; then
            sni=$(echo "$cert_path" | cut -d'/' -f4)
            insecure_flag=0
        fi
        
        if [[ "$sni" != "$HY2_SNI" && -n "$sni" ]]; then
            server_addr=$sni
            host_label=$sni
            client_args="${UDP2RAW_CLIENT_BASE_ARGS} -r ${server_addr}:${udp2raw_port} -l ${client_listen_addr} -k ${udp2raw_password}"
        fi
        
        # 检测混淆配置
        local obfs_password=""
        local obfs_param=""
        
        # 从配置文件中提取混淆密码（如果存在）
        sub_link="hysteria2://${hy2_password}@${client_udp2raw_host}:${client_udp2raw_port}?sni=${sni}&insecure=${insecure_flag}#Chain_hy2_${host_label}_${id}+UDP2RAW"
        local hy2_chain_clean="hysteria2://${hy2_password}@${client_udp2raw_host}:${client_udp2raw_port}?sni=${sni}&insecure=${insecure_flag}"
        local chain_name="chian_hy2+udp_${ip}_${id_num}"
        local chain_link="CHAIN://[${hy2_chain_clean} && udp2raw://${client_args}]#${chain_name}"
    fi

    cyan "--- ${title} 串联实例 ${id} 客户端配置 ---"; echo
    
    yellow "1. ${title} 客户端 (指向本地):"
    green "$sub_link"; echo
    
    yellow "2. UDP2RAW 客户端 (连接公网):"
    green "$client_args"; echo
    
    yellow "$display_title 合并订阅链接 (复制以下整行):"
    green "$chain_link"
    echo
}

# -----------------------------------------------------------------------------
# 启动一个新的 2 组件串联实例 (hy2 或 vless)
# -----------------------------------------------------------------------------
start_new_chain_instance() {
    local chain_type=$1
    local i=1 id_prefix="" title=""
    if [[ "$chain_type" == "hy2" ]]; then
        id_prefix="c"; title="Hysteria2+UDP"
        while true; do if ! jq -e --arg tag "hy2-c${i}" '.inbounds[] | select(.tag == $tag)' "$SINGBOX_INSTALL_DIR/singbox.json" >/dev/null 2>&1; then break; fi; i=$((i + 1)); done
    else
        yellow "不支持的串联类型"; return 1
    fi
    
    local chain_id="${id_prefix}${i}"
    log "启动一个新的 ${title} 串联实例..."
    green "新串联实例 #${i} (Hysteria2 + UDP2RAW 两层串联)"
    local chain_display_type="hy2_chain"
    prompt_custom_instance_name "$chain_display_type" "$i"
    
    # 先进行参数配置
    read_valid_port "请输入对外端口 (留空则随机生成): " udp2raw_listen_port true

    read_valid_port "请输入内联端口 (留空则随机生成): " internal_listen_port true
    
    # 添加Hysteria2串联实例的配置选项
    if [[ "$chain_type" == "hy2" ]]; then
        cyan "--- Hysteria2 配置 ---"
        read -p "ignoreClientBandwidth [true/false] (默认 true): " ignore_client_bandwidth
        ignore_client_bandwidth=${ignore_client_bandwidth:-true}
    fi
    
    
    local main_config="$main_conf_template"
    local main_conf_path=""
    
    if [[ "$chain_type" == "hy2" ]]; then
        local hy2_password=$(generate_strong_password); echo -n "已自动生成 Hysteria2 密码: "; green "$hy2_password"
        
        cyan "--- ACME证书 配置 ---"
        read -p "是否使用 ACME证书? (否则将使用自签名证书) [y/N] (默认"N"): " use_acme
        use_acme=${use_acme:-n}
        
        local cert_path="" key_path="" sni=""
        
        if [[ "$use_acme" == "y" || "$use_acme" == "Y" ]]; then
            read -p "请输入您的域名 (DNS 必须指向本机): " domain_name
            if [[ -z "$domain_name" ]]; then
                red "域名不能为空！已取消创建。"
                return 1
            fi

            if ! ensure_ax_script "$AX_ACME_SCRIPT" "$AX_ACME_URL"; then
                red "无法获取 $AX_ACME_SCRIPT，已取消创建实例。"
                return 1
            fi
            
            if ! bash "$AX_ACME_SCRIPT" -n "$domain_name"; then
                red "ACME 证书申请流程失败，已取消创建实例。"
                return 1
            fi
            
            if [ -f "$AX_CERT_DIR/$domain_name/fullchain.cer" ]; then
                green "ACME 验证成功. Hysteria2 将使用 $domain_name"
                cert_path="$AX_CERT_DIR/$domain_name/fullchain.cer"
                key_path="$AX_CERT_DIR/$domain_name/private.key"
                sni="$domain_name"
            else
                red "错误：未找到申请的证书文件，已取消创建实例。"
                return 1
            fi
        else
            generate_self_signed_cert
            cert_path="$HY2_CERT_PATH"
            key_path="$HY2_KEY_PATH"
            sni="$HY2_SNI"
        fi
        
        # 将 Hysteria2 inbound 添加到 singbox.json
        local hy2_inbound='{
            "type": "hysteria2",
            "tag": "hy2-c'"${i}"'",
            "listen": "127.0.0.1",
            "listen_port": '"${internal_listen_port}"',
            "up_mbps": 100,
            "down_mbps": 100,
            "users": [{"password": "'"${hy2_password}"'"}],
            "tls": {
                "enabled": true,
                "server_name": "'"${sni}"'",
                "key_path": "'"${key_path}"'",
                "certificate_path": "'"${cert_path}"'"
            }
        }'
        local config_file="$SINGBOX_INSTALL_DIR/singbox.json"
        if [[ ! -f "$config_file" ]]; then
            red "错误: 基础配置文件 $config_file 不存在！请先安装 Sing-box。"
            return 1
        fi
        local tmpfile=$(mktemp)
        jq --argjson inbound "$hy2_inbound" '.inbounds += [$inbound]' "$config_file" > "$tmpfile" && mv "$tmpfile" "$config_file"
    fi

    # 添加UDP2RAW串联实例的配置选项
    cyan "--- UDP2RAW 配置 ---"
    read -p "raw_mode [faketcp/udp/icmp] (默认 faketcp): " raw_mode
    raw_mode=${raw_mode:-faketcp}
    
    read -p "cipher_mode [aes128cbc/xor] (默认 aes128cbc): " cipher_mode
    cipher_mode=${cipher_mode:-aes128cbc}
    
    read -p "auth_mode [hmac_sha1/simple] (默认 hmac_sha1): " auth_mode
    auth_mode=${auth_mode:-hmac_sha1}
    
    # 然后生成密码
    local udp2raw_password=$(generate_strong_password); echo -n "已自动生成 UDP2RAW 密码: "; green "$udp2raw_password"

    log "生成 UDP2RAW 配置文件: udp2raw_${chain_id}.conf..."; local temp_udp_config="${UDP2RAW_CONFIG_TEMPLATE}"
    temp_udp_config="${temp_udp_config//__LISTEN_ADDR__/0.0.0.0:${udp2raw_listen_port}}"
    temp_udp_config="${temp_udp_config//__TARGET_ADDR__/127.0.0.1:${internal_listen_port}}"
    temp_udp_config="${temp_udp_config//__PASSWORD__/${udp2raw_password}}"
    temp_udp_config="${temp_udp_config//__RAW_MODE__/${raw_mode}}"
    temp_udp_config="${temp_udp_config//__CIPHER_MODE__/${cipher_mode}}"
    temp_udp_config="${temp_udp_config//__AUTH_MODE__/${auth_mode}}"
    
    local udp2raw_conf="$UDP2RAW_INSTALL_DIR/udp2raw_${chain_id}.conf"
    echo "$temp_udp_config" > "$udp2raw_conf"
    
    sync; log "启动串联服务...";
    systemctl restart ax-singbox.service
    systemctl enable --now "ax-udp2raw@${chain_id}.service"
    
    sleep 1; green "串联实例 ${chain_id} 已启动！"; echo
    view_chain_client_config "$chain_type" "$i"
}

# -----------------------------------------------------------------------------
# 管理 2 组件串联实例
# -----------------------------------------------------------------------------
manage_chain_instance() {
    local chain_type=$1 id_num=$2
    local id_prefix="" title="" service1_name="" service2_name="" main_conf_path=""
    local manage_type=""
    if [[ "$chain_type" == "hy2" ]]; then
        manage_type="hy2_chain"
    else
        yellow "不支持的串联类型"; return 1
    fi
    local disp_name=$(get_instance_display_name "$manage_type" "$id_num")
    
    if [[ "$chain_type" == "hy2" ]]; then
        id_prefix="c"; title="Hysteria2"; main_conf_path=""; service1_name="ax-singbox"
    fi
    
    local manage_id="${id_prefix}${id_num}"
    service2_name="udp2raw"
    local service1_full="${service1_name}.service"
    local service2_full="ax-udp2raw@${manage_id}.service"
    local udp2raw_conf_path="$UDP2RAW_INSTALL_DIR/udp2raw_${manage_id}.conf"
    
    while true; do
        clear; echo "=================================="; echo "      ${disp_name}  $(dim "(${manage_id})")"; echo "=================================="
        read -r color s1_status s2_status <<< "$(get_chain_status_tuple "$chain_type" "$manage_id")"
        local udp2raw_info=$(get_listen_info_from_conf "$udp2raw_conf_path")
        
        $color "状态: Hysteria2 [${s1_status}] + UDP2RAW [${s2_status}] $(dim "$udp2raw_info")"
 
        echo "----------------------------------"; echo "1) 启动/重启此串联"; echo "2) 停止此串联"; echo "3) 查看客户端配置"; echo "4) 查看 ${title} 日志"; echo "5) 查看 UDP2RAW 日志"; echo "6) 编辑 Sing-box 配置文件"; echo "7) 编辑 UDP2RAW 配置文件"; echo "8) 修改实例名称"; echo "99) 彻底删除此串联"; echo "0) 返回"
        read -p "请选择 [0-8, 99]: " manage_choice
        case $manage_choice in
            1) log "重启串联..."; systemctl restart "$service1_full" "$service2_full";;
            2) log "停止串联..."; systemctl stop "$service1_full" "$service2_full";;
            3) view_chain_client_config "$chain_type" "$id_num"; read -p $'\n按任意键返回...' -n1 -s;;
            4) 
                log "正在实时跟踪 ${title} 日志... (按 Ctrl+C 仅退出日志)"
                local current_trap=$(trap -p SIGINT)
                trap ':' SIGINT
                journalctl -u "$service1_full" -f
                eval "$current_trap"
                ;;
            5) 
                # 修复 Ctrl+C 问题
                log "正在实时跟踪 UDP2RAW 日志... (按 Ctrl+C 仅退出日志)"
                local current_trap=$(trap -p SIGINT)
                trap ':' SIGINT
                journalctl -u "$service2_full" -f
                eval "$current_trap"
                ;;
            6) nano "$main_conf_path"; systemctl restart "$service1_full";;
            7) nano "$udp2raw_conf_path"; systemctl restart "$service2_full";;
            8) interactive_rename_instance "$manage_type" "$id_num"; read -p $'\n按任意键返回...' -n1 -s;;
            99) read -p "确认删除串联实例 ${manage_id}？(默认“否”) [y/N]: " del_confirm; if [[ "$del_confirm" == "y" ]]; then 
                if [[ "$chain_type" == "hy2" ]]; then
                    # 从 singbox.json 移除对应的 inbound
                    local tag="hy2-c${id_num}"
                    remove_singbox_inbound "$tag"
                fi
                systemctl stop "$service2_full"; 
                systemctl disable "$service2_full" >/dev/null 2>&1; 
                rm -f "$udp2raw_conf_path"; 
                remove_custom_instance_name "${manage_type}_${id_num}"
                systemctl daemon-reload; green "已删除。"; break; 
                fi;;
            0) break;; *) red "无效输入";;
        esac
        [[ "$manage_choice" == "1" || "$manage_choice" == "2" || "$manage_choice" == "6" || "$manage_choice" == "7" ]] && read -p $'\n按任意键返回...' -n1 -s
    done
}

