# -----------------------------------------------------------------------------
# [新] 显示全局 TLS 证书状态
# -----------------------------------------------------------------------------
show_global_tls_status() {
    echo "--- TLS 证书状态 ---"
    
    # 检查 ACME 证书目录
    if [ ! -d "$AX_CERT_DIR" ] || [ -z "$(ls -A $AX_CERT_DIR)" ]; then
        yellow "未找到 ACME 证书。"
    else
        # 遍历 $AX_CERT_DIR 下的每个域名目录
        for domain_dir in "$AX_CERT_DIR"/*; do
            if [ -d "$domain_dir" ]; then
                local domain=$(basename "$domain_dir")
                local cert_file="$domain_dir/fullchain.cer"
                local key_file="$domain_dir/private.key"
                
                if [ -f "$cert_file" ] && [ -f "$key_file" ]; then
                    local expiry_date_str
                    local days_remaining="N/A"
                    
                    # 尝试获取到期天数
                    if command -v openssl &>/dev/null; then
                        expiry_date_str=$(openssl x509 -in "$cert_file" -noout -enddate 2>/dev/null | cut -d= -f2)
                        if [ -n "$expiry_date_str" ]; then
                            local expiry_epoch=$(date -d "$expiry_date_str" +%s 2>/dev/null)
                            local now_epoch=$(date +%s)
                            if [ -n "$expiry_epoch" ]; then
                                days_remaining=$(((expiry_epoch - now_epoch) / 86400))
                                days_remaining="(剩余 ${days_remaining} 天)"
                            fi
                        fi
                    fi
                    
                    cyan "[域名] $domain $days_remaining"
                    echo "  公钥 (Cert): $cert_file"
                    echo "  私钥 (Key):  $key_file"
                fi
            fi
        done
    fi
}

# -----------------------------------------------------------------------------
# [新] 显示 WARP 状态
# -----------------------------------------------------------------------------
show_warp_status() {
    echo "--- WARP 状态 ---"
    local warp_key_file="$SINGBOX_INSTALL_DIR/.warp_wireguard.json"
    if [[ -f "$warp_key_file" ]]; then
        local wg_private=$(jq -r '.private_key // empty' "$warp_key_file" 2>/dev/null)
        if [[ -n "$wg_private" ]]; then
            green "[Sing-box WireGuard] WARP 已注册"
            echo "账户类型: Free"
        fi
    else
        yellow "WARP 未配置 — 首次安装时自动注册 Sing-box WireGuard WARP"
    fi
}

# -----------------------------------------------------------------------------
# 查看全部实例的客户端配置
# -----------------------------------------------------------------------------
view_all_configs() {
    clear; echo "=================================="; echo "        查看全部实例配置"; echo "=================================="; echo
    
    local ss_3_chain_instances=$(get_chain_instances_3); if [[ -n "$ss_3_chain_instances" ]]; then for i in $ss_3_chain_instances; do view_chain_client_config_3 "$i"; echo "----------------------------------"; done; fi
    local hy2_chain_instances=$(get_chain_instances "hy2"); if [[ -n "$hy2_chain_instances" ]]; then for i in $hy2_chain_instances; do view_chain_client_config "hy2" "$i"; echo "----------------------------------"; done; fi
    
    local standalone_reality=($(get_standalone_instances "xray_reality")); if [[ ${#standalone_reality[@]} -gt 0 ]]; then echo; cyan "--- VLESS+Reality 独立模式订阅链接 ---"; echo 
    for id in "${standalone_reality[@]}"; do green "$(generate_singbox_reality_link $id)"; done; echo "----------------------------------"; fi
    local standalone_hy2=($(get_standalone_instances "hysteria2")); if [[ ${#standalone_hy2[@]} -gt 0 ]]; then echo; cyan "--- Hysteria2 独立模式订阅链接 ---"; echo
    for id in "${standalone_hy2[@]}"; do green "$(generate_singbox_hy2_link $id)"; done; echo "----------------------------------"; fi
    
    local standalone_udp2raw=($(get_standalone_instances "udp2raw")); if [[ ${#standalone_udp2raw[@]} -gt 0 ]]; then echo; for id in "${standalone_udp2raw[@]}"; do view_udp2raw_client_config "$id"; echo; done; echo "----------------------------------"; fi
    local standalone_kcptun=($(get_standalone_instances "kcptun")); if [[ ${#standalone_kcptun[@]} -gt 0 ]]; then echo; for id in "${standalone_kcptun[@]}"; do view_kcptun_client_config "$id"; echo; done; fi

    if ! is_installed; then yellow "系统中没有任何已配置的实例。"; fi
}

# -----------------------------------------------------------------------------
# 重启所有服务
# -----------------------------------------------------------------------------
restart_all_services() {
    log "正在重启所有正在运行的实例..."
    local count=0
    # Singleton sing-box service
    if systemctl is-active --quiet ax-singbox.service 2>/dev/null; then
        systemctl restart ax-singbox.service 2>/dev/null && count=$((count + 1))
    fi
    # Per-instance services (KCPTUN, UDP2RAW)
    for f in "$KCP_INSTALL_DIR"/kcptun_*.json "$UDP2RAW_INSTALL_DIR"/udp2raw_*.conf; do
        [[ -f "$f" ]] || continue
        local base=$(basename "$f")
        local id=""; local srv=""
        case "$base" in
            kcptun_*.json)   id="${base#kcptun_}"; id="${id%.json}";   srv="ax-kcptun@${id}" ;;
            udp2raw_*.conf)  id="${base#udp2raw_}"; id="${id%.conf}";  srv="ax-udp2raw@${id}" ;;
        esac
        [[ -n "$srv" ]] && systemctl restart "$srv" 2>/dev/null && count=$((count + 1))
    done
    green "已重启 ${count} 个实例"
    sleep 2
}

# -----------------------------------------------------------------------------
# 检查并更新所有核心程序
# -----------------------------------------------------------------------------
check_for_updates(){
    log "检查更新..."
    echo ""

     # 先停止所有服务
    log "正在停止全部服务以进行组件更新..."
    systemctl stop ax-singbox.service 2>/dev/null
    for f in "$KCP_INSTALL_DIR"/kcptun_*.json "$UDP2RAW_INSTALL_DIR"/udp2raw_*.conf; do
        [[ -f "$f" ]] || continue
        local base=$(basename "$f"); local srv=""
        case "$base" in
            kcptun_*.json)  srv="ax-kcptun@${base#kcptun_}"; srv="${srv%.json}" ;;
            udp2raw_*.conf) srv="ax-udp2raw@${base#udp2raw_}"; srv="${srv%.conf}" ;;
        esac
        [[ -n "$srv" ]] && systemctl stop "$srv" 2>/dev/null
    done
    sleep 2
    
    # ========== 第一部分：更新核心程序 ==========
    cyan "正在检查核心程序更新..."
    
    # 记录更新前的版本
    local kcp_before=$(cat "$KCP_INSTALL_DIR/version.txt" 2>/dev/null)
    local udp_before=$(cat "$UDP2RAW_INSTALL_DIR/version.txt" 2>/dev/null)
    local singbox_before=$(cat "$SINGBOX_INSTALL_DIR/version.txt" 2>/dev/null)
    
    # 执行更新检查与下载
    download_kcp_udp_binaries
    download_singbox_binary
    
    # 检查是否有任何更新
    local kcp_after=$(cat "$KCP_INSTALL_DIR/version.txt" 2>/dev/null)
    local udp_after=$(cat "$UDP2RAW_INSTALL_DIR/version.txt" 2>/dev/null)
    local singbox_after=$(cat "$SINGBOX_INSTALL_DIR/version.txt" 2>/dev/null)
    
    local has_updates=false
    if [[ "$kcp_before" != "$kcp_after" ]] || [[ "$udp_before" != "$udp_after" ]] || \
       [[ "$singbox_before" != "$singbox_after" ]]; then
        has_updates=true
    fi
    
    # 无论是否有更新，都要重启之前被停止的服务
    if [[ "$has_updates" == true ]]; then
        green "核心程序已更新，重启服务中..."
    else
        green "核心程序均已是最新版本，重启服务中..."
    fi
    restart_all_services
    sleep 2
    
    # ========== 第二部分：更新辅助脚本 ==========
    echo ""
    cyan "正在检查辅助脚本更新..."
    
    local script_updated=false
    
    # 更新 ACME 证书管理脚本
    if [[ -f "$AX_ACME_SCRIPT" ]]; then
        cyan "  » 更新 $AX_ACME_SCRIPT"
        download_with_retry "$AX_ACME_URL" "$AX_ACME_SCRIPT" >/dev/null 2>&1 && chmod +x "$AX_ACME_SCRIPT" && green "    ✓ $AX_ACME_SCRIPT 更新完成" && script_updated=true || yellow "    ⚠ $AX_ACME_SCRIPT 更新失败"
    fi
    
    # 更新 VPS 优化脚本
    if [[ -f "$AX_OPTZ_SCRIPT" ]]; then
        cyan "  » 更新 $AX_OPTZ_SCRIPT"
        download_with_retry "$AX_OPTZ_URL" "$AX_OPTZ_SCRIPT" >/dev/null 2>&1 && chmod +x "$AX_OPTZ_SCRIPT" && green "    ✓ $AX_OPTZ_SCRIPT 更新完成" && script_updated=true || yellow "    ⚠ $AX_OPTZ_SCRIPT 更新失败"
    fi
    
    if [[ "$script_updated" == false ]]; then
        green "辅助脚本均已是最新版本。"
    fi
    
    echo ""
    green "✓ 所有更新检查完成！"
    echo ""
}

# -----------------------------------------------------------------------------
# 通用本地脚本执行函数
# 参数: $1=本地脚本文件名, $2=脚本描述名称, $3=脚本URL（用于下载）
# -----------------------------------------------------------------------------
run_local_script() {
    local script_file=$1
    local script_name=$2
    local script_url=$3
    
    echo "----------------------------------------------------------------"
    log "即将开始运行 ${script_name}..."
    echo ""
    
    # 检查本地脚本是否存在，如果不存在则下载
    if [[ ! -f "$script_file" ]]; then
        yellow "本地脚本不存在，正在下载..."
        download_with_retry "$script_url" "$script_file" || { red "脚本下载失败！"; return 1; }
        chmod +x "$script_file"
        green "脚本下载完成。"
    fi
    
    # 执行本地脚本
    ./$script_file
    
    echo ""
    echo "----------------------------------------------------------------"
    green "${script_name}执行完毕。"
    log "即将返回主菜单..."
}

# -----------------------------------------------------------------------------
# 安装 VPS 一键优化脚本
# -----------------------------------------------------------------------------
install_sys_opt() {
    run_local_script "$AX_OPTZ_SCRIPT" "VPS 优化脚本" "$AX_OPTZ_URL"
}

# -----------------------------------------------------------------------------
# 卸载所有 (REFACTORED: 修复软卸载路径)
# -----------------------------------------------------------------------------
uninstall_all() {
    read -p "确认要卸载吗？(默认“否”) [y/N]: " confirm
    if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then 
        yellow "操作已取消。"
        return 1
    fi
    
    read -p "是否要执行彻底清理（删除所有配置文件，保留证书）？(默认“否”) [y/N]: " nuke_choice
    log "开始卸载流程..."
    log "步骤 1: 停止并禁用所有相关服务..."
    systemctl stop ax-singbox.service 2>/dev/null; systemctl disable ax-singbox.service 2>/dev/null
    for srv in ax-kcptun@* ax-udp2raw@*; do systemctl stop "$srv" 2>/dev/null; systemctl disable "$srv" 2>/dev/null; done
    green "服务已停止并禁用。"
    log "步骤 2: 删除所有 systemd 服务文件..."
    rm -f "$KCPTUN_TEMPLATE_FILE" \
          "$UDP2RAW_TEMPLATE_FILE" \
          "$SINGBOX_TEMPLATE_FILE"
    green "Systemd 服务文件已删除。"
    if [[ "$nuke_choice" == "y" || "$nuke_choice" == "Y" ]]; then
        log "步骤 3: 执行彻底清理..."
        rm -rf "$KCP_INSTALL_DIR" "$UDP2RAW_INSTALL_DIR" "$SINGBOX_INSTALL_DIR"
        green "程序和配置文件目录已删除 (证书已保留)。"

        # 步骤 4: 清理证书客户端（完全卸载模式）
        if [ -d "/root/.acme.sh" ]; then
            log "正在清理 $AX_ACME_SCRIPT 证书客户端..."
            if [ ! -f "$AX_ACME_SCRIPT" ]; then
                if ! ensure_ax_script "$AX_ACME_SCRIPT" "$AX_ACME_URL"; then
                    yellow "无法下载 $AX_ACME_SCRIPT，将跳过 ACME 卸载。"
                fi
            fi
            if [ -f "$AX_ACME_SCRIPT" ] && bash "$AX_ACME_SCRIPT" -u; then
                green "$AX_ACME_SCRIPT 证书客户端已删除。"
            else
                yellow "警告: $AX_ACME_SCRIPT 卸载可能未完全成功。"
            fi
        else
            log "未检测到 $AX_ACME_SCRIPT 客户端，跳过清理。"
        fi
    else
        log "步骤 3: 执行软卸载 (仅删除二进制文件和 dat 文件)..."
        rm -f "$KCP_INSTALL_DIR/kcptun_server" "$UDP2RAW_INSTALL_DIR/udp2raw"
        rm -f "$SINGBOX_INSTALL_DIR/sing-box" "$SINGBOX_INSTALL_DIR/.reality_keys.json"
        green "程序文件已删除。"
    fi
    log "步骤 4: 清理残留的程序和数据..."
    rm -f /usr/local/bin/hysteria
    rm -rf /etc/xray /etc/hysteria2
    green "残留程序和数据已清理。"
    log "步骤 5: 清理临时文件..."
    rm -f /tmp/kcptun.tar.gz /tmp/udp2raw.tar.gz /tmp/singbox.tar.gz
    log "步骤 6: 重载 systemd 并清理状态..."
    systemctl daemon-reload; systemctl reset-failed
    green "Systemd 已重载并清理。"
    
    echo; green "==== 卸载完成！ ===="
    yellow "提示：依赖包 (如 curl, openssl, jq, acme证书) 未被卸载。"
    yellow "提示：请手动删除此脚本文件。"
    
    sleep 3
    return 0
}

# =============================================================================
# 20. 脚本入口与初始化
# =============================================================================

# -----------------------------------------------------------------------------
# 系统兼容性检查函数
# -----------------------------------------------------------------------------
check_system_compatibility() {
    # 检查是否为root用户
    if [[ $EUID -ne 0 ]]; then
        red "错误: 此脚本必须以root用户身份运行"
        exit 1
    fi
    
    # 检查系统是否使用systemd
    if ! command -v systemctl &> /dev/null; then
        red "错误: 此脚本需要systemd支持，但您的系统似乎没有安装systemd"
        exit 1
    fi
    
    # 检查必要的命令是否可用
    local required_commands=("curl" "wget" "jq" "openssl")
    local missing_commands=()
    
    for cmd in "${required_commands[@]}"; do
        if ! command -v "$cmd" &> /dev/null; then
            missing_commands+=("$cmd")
        fi
    done
    
}

# -----------------------------------------------------------------------------
# 首次运行检查和安装核心程序
# -----------------------------------------------------------------------------
initial_check_and_install() {
    # 添加系统兼容性检查
    check_system_compatibility
    
    # 使用统一的安装函数
    install_dependencies_and_programs || { red "安装失败，退出脚本。"; exit 1; }
    
    # 确保模板文件就绪
    ensure_template_files
    sleep 1
}

# -----------------------------------------------------------------------------
# 主菜单状态总览 (使用粗体标题)
# -----------------------------------------------------------------------------
show_status_summary() {
    local menu_index=21; echo "--- 当前状态 (输入序号可直接管理) ---"; if ! is_installed; then yellow "未安装任何组件。"; return; fi
    
    local ss_3_chain_instances=$(get_chain_instances_3)
    if [[ -n "$ss_3_chain_instances" ]]; then
        echo "$(bold "SS+KCP+UDP 串联模式:")"
        for i in $ss_3_chain_instances; do display_instance_status_line "ss_3_chain_chain" "$i" "$menu_index) "; QUICK_MANAGE_MAP_ID[$menu_index]=$i; QUICK_MANAGE_MAP_TYPE[$menu_index]="ss_3_chain_chain"; menu_index=$((menu_index + 1)); done
    fi
    local hy2_chain_instances=$(get_chain_instances "hy2")
    if [[ -n "$hy2_chain_instances" ]]; then
        echo "$(bold "Hysteria2+UDP 串联模式:")"
        for i in $hy2_chain_instances; do display_instance_status_line "hy2_chain" "$i" "$menu_index) "; QUICK_MANAGE_MAP_ID[$menu_index]=$i; QUICK_MANAGE_MAP_TYPE[$menu_index]="hy2_chain"; menu_index=$((menu_index + 1)); done
    fi
    for type in "VLESS+Reality" "Hysteria2" "UDP2RAW" "KCPTUN"; do
        local type_lowercase=""
        case "$type" in
            "VLESS+Reality") type_lowercase="xray_reality";;
            "Hysteria2") type_lowercase="hysteria2";;
            "UDP2RAW") type_lowercase="udp2raw";;
            "KCPTUN") type_lowercase="kcptun";;
        esac
        
        local standalone_instances=($(get_standalone_instances "$type_lowercase"))

        if [[ ${#standalone_instances[@]} -gt 0 ]]; then
            echo "$(bold "${type} 独立模式:")"
            for i in "${standalone_instances[@]}"; do
                display_instance_status_line "$type_lowercase" "$i" "$menu_index) "
                QUICK_MANAGE_MAP_ID[$menu_index]=$i; QUICK_MANAGE_MAP_TYPE[$menu_index]="$type_lowercase"; menu_index=$((menu_index + 1))
            done
        fi
    done
}

# -----------------------------------------------------------------------------
# 主菜单 
# -----------------------------------------------------------------------------
main_menu(){
    declare -A QUICK_MANAGE_MAP_ID; declare -A QUICK_MANAGE_MAP_TYPE
    while true; do
        QUICK_MANAGE_MAP_ID=(); QUICK_MANAGE_MAP_TYPE=()
        trap '' SIGINT
        clear; echo "=================================="; echo "  多合一隧道管理脚本 V$SCRIPT_VERSION"; echo "=================================="
        cyan "--- 串联模式 ---"
        echo " 1) Shadowsocks+KCP+UDP 串联"
        echo " 2) Hysteria2+UDP2RAW 串联"
        cyan "--- 独立模式 ---"
        echo " 3) VLESS+Reality"
        echo " 4) Hysteria2"
        cyan "--- 组件管理 ---"
        echo " 5) UDP2RAW"
        echo " 6) KCPTUN"
        echo "----------------------------------"
        cyan "--- 全局操作 ---"
        echo " 7) 查看全部配置"
        echo " 8) 重启全部服务"
        echo " 9) 检查更新程序" 
        cyan "--- 工具管理 ---"
        echo " 10) 运行VPS优化脚本"
        echo " 11) ACME证书管理"
        echo "----------------------------------"   
        echo " 99) 卸载"
        echo "----------------------------------"   
        echo " 0) 退出"
        echo "----------------------------------"
        show_global_tls_status
        echo "----------------------------------"
        show_warp_status
        echo "----------------------------------"
        show_status_summary
        local num_items=${#QUICK_MANAGE_MAP_ID[@]}; local max_index=$((20 + num_items))
        echo "----------------------------------"
        local prompt="请选择 [0-11, 99"; if [[ $num_items -gt 0 ]]; then prompt+=", 21-${max_index}]"; else prompt+="]"; fi
        read -p "$prompt： " choice
        
        if [[ -n "$choice" && -n "${QUICK_MANAGE_MAP_ID[$choice]}" ]]; then
            local real_id="${QUICK_MANAGE_MAP_ID[$choice]}"; local type="${QUICK_MANAGE_MAP_TYPE[$choice]}"
            case "$type" in
                "ss_3_chain_chain") manage_chain_instance_3 "$real_id" ;;
                "hy2_chain") manage_chain_instance "hy2" "$real_id" ;;
                "xray_reality") manage_instance_menu "xray_reality" "$real_id" "ax-singbox" "$SINGBOX_INSTALL_DIR/singbox.json" ;;
                "hysteria2") manage_instance_menu "hysteria2" "$real_id" "ax-singbox" "$SINGBOX_INSTALL_DIR/singbox.json" ;;
                "udp2raw") manage_instance_menu "udp2raw" "$real_id" "ax-udp2raw@${real_id}" "$UDP2RAW_INSTALL_DIR/udp2raw_${real_id}.conf" ;;
                "kcptun") manage_instance_menu "kcptun" "$real_id" "ax-kcptun@${real_id}" "$KCP_INSTALL_DIR/kcptun_${real_id}.json" ;;
            esac
            continue
        fi
        
        case $choice in
            1) chain_manager_menu_3 ;;
            2) chain_manager_menu "hy2" ;;
            3) main_manager_loop "xray_reality" ;;
            4) main_manager_loop "hysteria2" ;;
            5) main_manager_loop "udp2raw" ;;
            6) main_manager_loop "kcptun" ;;
            7) view_all_configs; read -p $'\n按任意键返回...' -n1 -s;;
            8) restart_all_services ;;
            9) check_for_updates; read -p "按任意键继续..." -n1 -s ;;
            10) clear; install_sys_opt; read -p $'\n按任意键返回...' -n1 -s ;;
            11) clear; run_local_script "$AX_ACME_SCRIPT" "ACME 证书管理" "$AX_ACME_URL"; read -p $'\n按任意键返回...' -n1 -s ;;
            99) uninstall_all; if [[ $? -eq 0 ]]; then exit 0; fi ;;
            0) trap - SIGINT; exit 0 ;; 
            *) red "无效选择!"; sleep 1 ;;
        esac
    done
}

# =============================================================================
# 21. 脚本执行入口 (仅在直接执行时运行, source 导入函数时不执行)
# =============================================================================
if [[ "${BASH_SOURCE[0]}" == "${0}" ]]; then
    echo -e "\033[1;36m[INFO] 脚本启动... 当前版本: v${SCRIPT_VERSION}\033[0m"
    sleep 2
    # 捕获 Ctrl+C 信号，以便在脚本主体执行期间优雅退出
    trap 'echo -e "\n\n${yellow}操作被中断，退出脚本。${reset}"; trap - SIGINT; exit 1' SIGINT
    # 先运行 VPS 优化脚本
    install_sys_opt
    # 初始化检查和安装
    initial_check_and_install
    # 显示主菜单
    main_menu
fi
